var QUESTIONS_THEORY_11 = [
{type:"mcq",diff:"easy",en:{q:"What does HTML stand for in web development?",opts:["HyperText Machine Language","HyperText Markup Language","Hyper Transfer Markup Language","High-level Text Markup Language"],ans:1,exp:"HTML stands for HyperText Markup Language. It is the universally accepted standard markup language used to design and structure the foundational layout of web pages. It utilizes a standardized system of tags and attributes to instruct web browsers on how to display textual and multimedia content."},hi:{q:"वेब डेवलपमेंट में HTML का पूर्ण रूप क्या है?",opts:["हाइपरटेक्स्ट मशीन लैंग्वेज","हाइपरटेक्स्ट मार्कअप लैंग्वेज (HyperText Markup Language)","हाइपर ट्रांसफर मार्कअप लैंग्वेज","हाई-लेवल टेक्स्ट मार्कअप लैंग्वेज"],ans:1,exp:"HTML का पूर्ण रूप हाइपरटेक्स्ट मार्कअप लैंग्वेज है। यह वेब पेजों के मूलभूत लेआउट को डिजाइन और संरचित करने के लिए उपयोग की जाने वाली सार्वभौमिक रूप से स्वीकृत मानक मार्कअप भाषा है। यह वेब ब्राउज़र को टेक्स्ट और मल्टीमीडिया सामग्री प्रदर्शित करने का निर्देश देने के लिए टैग और विशेषताओं की एक मानकीकृत प्रणाली का उपयोग करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the core purpose of CSS in web design?",opts:["To create databases","To define the structural layout of a page","To style and visually format HTML elements","To execute server-side logic"],ans:2,exp:"CSS stands for Cascading Style Sheets. While HTML is strictly responsible for building the raw structural framework of a webpage, CSS is the design language used to completely control its visual presentation. CSS dictates aesthetic properties such as colors, typography, spacing, and responsive layouts across different screen sizes."},hi:{q:"वेब डिज़ाइन में CSS का मुख्य उद्देश्य क्या है?",opts:["डेटाबेस बनाने के लिए","पृष्ठ के संरचनात्मक लेआउट को परिभाषित करने के लिए","HTML तत्वों को स्टाइल और विज़ुअली फ़ॉर्मेट करने के लिए","सर्वर-साइड लॉजिक निष्पादित करने के लिए"],ans:2,exp:"CSS का अर्थ कैस्केडिंग स्टाइल शीट्स है। जबकि HTML वेबपेज के कच्चे संरचनात्मक ढांचे के निर्माण के लिए सख्ती से जिम्मेदार है, CSS एक डिज़ाइन भाषा है जिसका उपयोग इसकी दृश्य प्रस्तुति को पूरी तरह से नियंत्रित करने के लिए किया जाता है। CSS विभिन्न स्क्रीन आकारों में रंग, टाइपोग्राफी और रिक्ति जैसे सौंदर्य गुणों को निर्धारित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is the standard file extension for saving a basic HTML webpage?",opts:[".htm or .html",".web",".css",".txt"],ans:0,exp:"To be correctly recognized and interpreted by a web browser, a markup file must be saved with either a '.html' or '.htm' extension. When the browser encounters this extension, it actively parses the underlying markup tags and renders them into a graphical user interface rather than displaying raw plain text."},hi:{q:"बेसिक HTML वेबपेज को सेव करने के लिए मानक फाइल एक्सटेंशन निम्नलिखित में से कौन सा है?",opts:[".htm या .html",".web",".css",".txt"],ans:0,exp:"वेब ब्राउज़र द्वारा सही ढंग से पहचाने जाने और व्याख्या करने के लिए, मार्कअप फ़ाइल को '.html' या '.htm' एक्सटेंशन के साथ सहेजा जाना चाहिए। जब ब्राउज़र इस एक्सटेंशन का सामना करता है, तो यह अंतर्निहित मार्कअप टैग को पार्स करता है और कच्चे सादे पाठ को प्रदर्शित करने के बजाय उन्हें ग्राफिकल यूजर इंटरफेस में प्रस्तुत करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is specifically used to define the largest and most important heading on a webpage?",opts:["<h6>","<heading>","<h1>","<head>"],ans:2,exp:"HTML provides six distinct levels of headings, ranging numerically from <h1> to <h6>. The <h1> tag explicitly defines the most important, top-level heading of a page, and is rendered by default with the largest font size and boldest weight. It is highly critical for SEO and document structure."},hi:{q:"वेबपेज पर सबसे बड़े और सबसे महत्वपूर्ण शीर्षक (heading) को परिभाषित करने के लिए विशेष रूप से किस HTML टैग का उपयोग किया जाता है?",opts:["<h6>","<heading>","<h1>","<head>"],ans:2,exp:"HTML शीर्षकों के छह अलग-अलग स्तर प्रदान करता है, जो संख्यात्मक रूप से <h1> से <h6> तक होते हैं। <h1> टैग किसी पृष्ठ के सबसे महत्वपूर्ण, शीर्ष-स्तरीय शीर्षक को स्पष्ट रूप से परिभाषित करता है, और डिफ़ॉल्ट रूप से सबसे बड़े फ़ॉन्ट आकार और सबसे बोल्ड वजन के साथ प्रस्तुत किया जाता है। यह एसईओ और दस्तावेज़ संरचना के लिए अत्यधिक महत्वपूर्ण है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is universally used to define a standard block of text or a paragraph?",opts:["<para>","<p>","<text>","<pg>"],ans:1,exp:"The `<p>` tag defines a paragraph in HTML. It is a fundamental block-level element, meaning it automatically forces a line break before and after the text it encloses, separating it from adjacent elements. Browsers inherently add margin space above and below paragraph elements to improve readability."},hi:{q:"टेक्स्ट या पैराग्राफ के मानक ब्लॉक को परिभाषित करने के लिए सार्वभौमिक रूप से किस HTML टैग का उपयोग किया जाता है?",opts:["<para>","<p>","<text>","<pg>"],ans:1,exp:"`<p>` टैग HTML में एक पैराग्राफ को परिभाषित करता है। यह एक मूलभूत ब्लॉक-स्तरीय तत्व है, जिसका अर्थ है कि यह स्वचालित रूप से संलग्न पाठ के पहले और बाद में एक लाइन ब्रेक को मजबूर करता है। पठनीयता में सुधार के लिए ब्राउज़र स्वाभाविक रूप से पैराग्राफ तत्वों के ऊपर और नीचे मार्जिन स्पेस जोड़ते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is utilized to force a line break without initiating a new paragraph?",opts:["<break>","<lb>","<br>","<newline>"],ans:2,exp:"The `<br>` tag inserts a single physical line break directly within text. Unlike the `<p>` tag, it is an 'empty' or 'void' element, meaning it absolutely does not require a closing tag (like `</br>`). It forces text to immediately drop to the next line without adding the vertical spacing typically associated with paragraphs."},hi:{q:"नया पैराग्राफ शुरू किए बिना लाइन ब्रेक (line break) को मजबूर करने के लिए किस टैग का उपयोग किया जाता है?",opts:["<break>","<lb>","<br>","<newline>"],ans:2,exp:"`<br>` टैग टेक्स्ट के भीतर सीधे सिंगल फिजिकल लाइन ब्रेक डालता है। `<p>` टैग के विपरीत, यह एक 'खाली' या 'शून्य' (void) तत्व है, जिसका अर्थ है कि इसे बिल्कुल बंद करने वाले टैग (जैसे `</br>`) की आवश्यकता नहीं है। यह पैराग्राफ से जुड़े ऊर्ध्वाधर अंतर को जोड़े बिना पाठ को तुरंत अगली पंक्ति में छोड़ने के लिए मजबूर करता है।"}},
{type:"mcq",diff:"easy",en:{q:"In a standard HTML document, which tag physically encompasses all the visible content displayed in the browser window?",opts:["<head>","<body>","<html>","<content>"],ans:1,exp:"The `<body>` tag encapsulates the entire visible payload of an HTML document. Everything that a user actually sees rendered in the browser viewport—including paragraphs, images, hyperlinks, tables, and lists—must be placed strictly within the opening `<body>` and closing `</body>` tags."},hi:{q:"एक मानक HTML दस्तावेज़ में, कौन सा टैग भौतिक रूप से ब्राउज़र विंडो में प्रदर्शित सभी दृश्य सामग्री (visible content) को शामिल करता है?",opts:["<head>","<body>","<html>","<content>"],ans:1,exp:"`<body>` टैग HTML दस्तावेज़ के संपूर्ण दृश्यमान पेलोड को समाहित करता है। उपयोगकर्ता वास्तव में ब्राउज़र व्यूपोर्ट में जो कुछ भी प्रस्तुत करता है - जिसमें पैराग्राफ, चित्र, हाइपरलिंक, टेबल और सूचियां शामिल हैं - उन्हें शुरुआती `<body>` और अंतिम `</body>` टैग के भीतर कड़ाई से रखा जाना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"Which section of an HTML document contains metadata, the page title, and links to external CSS files, but is NOT displayed directly to the user?",opts:["<body>","<header>","<title>","<head>"],ans:3,exp:"The `<head>` element is the hidden administrative container of an HTML file. It holds vital metadata about the document, such as character set declarations, viewport settings for responsiveness, the `<title>` shown in the browser tab, and linking tags pointing to external CSS stylesheets and JavaScript files."},hi:{q:"HTML दस्तावेज़ के किस भाग में मेटाडेटा, पृष्ठ शीर्षक और बाहरी CSS फ़ाइलों के लिंक होते हैं, लेकिन उपयोगकर्ता को सीधे प्रदर्शित नहीं किए जाते हैं?",opts:["<body>","<header>","<title>","<head>"],ans:3,exp:"`<head>` तत्व एक HTML फ़ाइल का छिपा हुआ प्रशासनिक कंटेनर है। यह दस्तावेज़ के बारे में महत्वपूर्ण मेटाडेटा रखता है, जैसे कैरेक्टर सेट डिक्लेरेशन, रिस्पॉन्सिबिलिटी के लिए व्यूपोर्ट सेटिंग्स, ब्राउज़र टैब में दिखाया गया `<title>`, और बाहरी CSS स्टाइलशीट और जावास्क्रिप्ट फ़ाइलों को इंगित करने वाले लिंकिंग टैग।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is specifically required to embed an external CSS stylesheet into an HTML document?",opts:["<style>","<css>","<script>","<link>"],ans:3,exp:"The `<link>` tag is exclusively used within the `<head>` section to establish connections with external resources. To apply external CSS, the syntax requires `<link rel=\"stylesheet\" href=\"styles.css\">`. This tells the browser to fetch the external CSS file and apply its formatting rules to the HTML structure."},hi:{q:"HTML दस्तावेज़ में बाहरी CSS स्टाइलशीट को एम्बेड करने के लिए विशेष रूप से किस टैग की आवश्यकता होती है?",opts:["<style>","<css>","<script>","<link>"],ans:3,exp:"`<link>` टैग का विशेष रूप से बाहरी संसाधनों के साथ कनेक्शन स्थापित करने के लिए `<head>` अनुभाग के भीतर उपयोग किया जाता है। बाहरी CSS लागू करने के लिए, सिंटैक्स को `<link rel=\"stylesheet\" href=\"styles.css\">` की आवश्यकता होती है। यह ब्राउज़र को बाहरी सीएसएस फ़ाइल लाने और उसके स्वरूपण नियमों को लागू करने के लिए कहता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which CSS property is fundamentally used to change the text color of an HTML element?",opts:["text-color","font-color","color","text-style"],ans:2,exp:"In CSS terminology, the `color` property specifically dictates the foreground color of text content within an element. It can accept various value formats, including named colors (e.g., 'red'), Hexadecimal codes (e.g., '#FF0000'), or RGB values (e.g., 'rgb(255,0,0)')."},hi:{q:"HTML तत्व के टेक्स्ट का रंग बदलने के लिए मौलिक रूप से किस CSS प्रॉपर्टी का उपयोग किया जाता है?",opts:["text-color","font-color","color","text-style"],ans:2,exp:"CSS शब्दावली में, `color` संपत्ति विशेष रूप से एक तत्व के भीतर पाठ सामग्री के अग्रभूमि रंग को निर्धारित करती है। यह नामित रंग (जैसे, 'लाल'), हेक्साडेसिमल कोड (जैसे, '#FF0000'), या RGB मान (जैसे, 'rgb(255,0,0)') सहित विभिन्न मूल्य स्वरूपों को स्वीकार कर सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What CSS property is used to set the background color of an element or the entire page?",opts:["bg-color","background-color","color-background","back-color"],ans:1,exp:"The `background-color` property defines the exact solid color that fills the background area of an HTML element. When applied to the `body` selector in CSS (e.g., `body { background-color: lightblue; }`), it effectively paints the entire background of the web browser's viewing area."},hi:{q:"किसी तत्व या पूरे पृष्ठ का पृष्ठभूमि रंग (background color) सेट करने के लिए किस CSS प्रॉपर्टी का उपयोग किया जाता है?",opts:["bg-color","background-color","color-background","back-color"],ans:1,exp:"`background-color` संपत्ति सटीक ठोस रंग को परिभाषित करती है जो HTML तत्व के पृष्ठभूमि क्षेत्र को भरती है। जब CSS में `body` चयनकर्ता पर लागू किया जाता है (उदा., `body { background-color: lightblue; }`), तो यह वेब ब्राउज़र के देखने के क्षेत्र की संपूर्ण पृष्ठभूमि को प्रभावी ढंग से पेंट करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which traditional HTML tag is used to make text visually bold?",opts:["<bold>","<b>","<heavy>","<strong>"],ans:1,exp:"The `<b>` tag is the traditional physical markup tag used to render enclosed text in a bold typeface without conveying any extra semantic importance. Modern HTML5 also provides the `<strong>` tag, which visually bolds text but critically adds semantic weight, indicating that the text is of strong importance for screen readers."},hi:{q:"टेक्स्ट को विज़ुअली बोल्ड (bold) बनाने के लिए किस पारंपरिक HTML टैग का उपयोग किया जाता है?",opts:["<bold>","<b>","<heavy>","<strong>"],ans:1,exp:"`<b>` टैग एक पारंपरिक भौतिक मार्कअप टैग है जिसका उपयोग संलग्न पाठ को बिना कोई अतिरिक्त अर्थ संबंधी महत्व बताए बोल्ड टाइपफेस में प्रस्तुत करने के लिए किया जाता है। आधुनिक HTML5 `<strong>` टैग भी प्रदान करता है, जो टेक्स्ट को बोल्ड करता है लेकिन अर्थपूर्ण वजन जोड़ता है, यह दर्शाता है कि टेक्स्ट बहुत महत्वपूर्ण है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is used to display text in italics?",opts:["<i>","<italic>","<em>","<it>"],ans:0,exp:"The `<i>` tag is utilized to format text in an italicized style purely for visual differentiation, often used for technical terms or foreign phrases. Similarly to bolding, the `<em>` (emphasis) tag also renders text in italics but adds vital semantic emphasis recognized by assistive technologies."},hi:{q:"टेक्स्ट को इटैलिक (तिरछे) में प्रदर्शित करने के लिए किस HTML टैग का उपयोग किया जाता है?",opts:["<i>","<italic>","<em>","<it>"],ans:0,exp:"`<i>` टैग का उपयोग केवल दृश्य विभेदन के लिए इटैलिकाइज़्ड शैली में टेक्स्ट को प्रारूपित करने के लिए किया जाता है, जिसका उपयोग अक्सर तकनीकी शब्दों या विदेशी वाक्यांशों के लिए किया जाता है। बोल्डिंग के समान, `<em>` (जोर) टैग भी इटैलिक में पाठ प्रस्तुत करता है लेकिन सहायक तकनीकों द्वारा मान्यता प्राप्त महत्वपूर्ण अर्थ संबंधी जोर जोड़ता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is used to draw an underline beneath text?",opts:["<underline>","<line>","<u>","<uln>"],ans:2,exp:"The `<u>` tag physically underlines the text enclosed within it. While highly common in older HTML versions, its use is heavily discouraged in modern web design because underlined text is universally associated with clickable hyperlinks, potentially confusing the user. CSS `text-decoration: underline;` is the modern standard."},hi:{q:"टेक्स्ट के नीचे अंडरलाइन खींचने के लिए किस टैग का उपयोग किया जाता है?",opts:["<underline>","<line>","<u>","<uln>"],ans:2,exp:"`<u>` टैग भौतिक रूप से इसके भीतर संलग्न पाठ को रेखांकित करता है। यद्यपि पुराने HTML संस्करणों में अत्यधिक आम है, आधुनिक वेब डिज़ाइन में इसके उपयोग को बहुत हतोत्साहित किया जाता है क्योंकि रेखांकित पाठ सार्वभौमिक रूप से क्लिक करने योग्य हाइपरलिंक से जुड़ा होता है, जो संभावित रूप से उपयोगकर्ता को भ्रमित करता है। CSS `text-decoration: underline;` आधुनिक मानक है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary role of a Web Browser?",opts:["To create graphical images","To compile C++ code","To interpret HTML, CSS, and JS code and graphically display web pages","To host websites on a server"],ans:2,exp:"A Web Browser (like Chrome, Firefox, or Edge) is a dedicated client software engine. Its primary job is to fetch raw source code (HTML, CSS, JavaScript) from a web server across the internet, parse the markup tags and CSS rules, and graphically render the final visual layout for the user to interact with."},hi:{q:"वेब ब्राउज़र (Web Browser) की प्राथमिक भूमिका क्या है?",opts:["ग्राफिकल चित्र बनाने के लिए","C++ कोड संकलित (compile) करने के लिए","HTML, CSS और JS कोड की व्याख्या करने और वेब पेजों को ग्राफिक रूप से प्रदर्शित करने के लिए","सर्वर पर वेबसाइटों को होस्ट करने के लिए"],ans:2,exp:"वेब ब्राउज़र (जैसे क्रोम, फ़ायरफ़ॉक्स या एज) एक समर्पित क्लाइंट सॉफ़्टवेयर इंजन है। इसका प्राथमिक काम इंटरनेट पर वेब सर्वर से कच्चा स्रोत कोड (HTML, CSS, JavaScript) प्राप्त करना, मार्कअप टैग और CSS नियमों को पार्स करना और उपयोगकर्ता के साथ बातचीत करने के लिए अंतिम दृश्य लेआउट को ग्राफिक रूप से प्रस्तुत करना है।"}},
{type:"mcq",diff:"easy",en:{q:"Which CSS property dictates the size of the text?",opts:["font-weight","text-size","text-style","font-size"],ans:3,exp:"The `font-size` property in CSS explicitly controls the physical scale and dimensions of typography. It accepts various absolute or relative measurement units, such as pixels (px), ems (em), root ems (rem), or percentages (%), allowing developers fine-grained control over text readability."},hi:{q:"कौन सी CSS संपत्ति (property) टेक्स्ट के आकार को निर्धारित करती है?",opts:["font-weight","text-size","text-style","font-size"],ans:3,exp:"CSS में `font-size` प्रॉपर्टी स्पष्ट रूप से टाइपोग्राफी के भौतिक पैमाने और आयामों को नियंत्रित करती है। यह विभिन्न पूर्ण या सापेक्ष माप इकाइयों को स्वीकार करता है, जैसे कि पिक्सल (px), ems (em), रूट ems (rem), या प्रतिशत (%), जिससे डेवलपर्स को टेक्स्ट पठनीयता पर ठीक-ठीक नियंत्रण मिलता है।"}},
{type:"mcq",diff:"easy",en:{q:"How many standardized heading tags (levels) does HTML natively support?",opts:["4","5","6","7"],ans:2,exp:"HTML rigidly defines exactly six hierarchical heading elements, sequentially numbered from `<h1>` down to `<h6>`. `<h1>` defines the most prominent, top-level section, while `<h6>` defines the smallest, lowest-level subsection. Proper sequential use of these tags is essential for accessibility screen readers."},hi:{q:"HTML मूल रूप से कितने मानकीकृत शीर्षक टैग (स्तर) का समर्थन करता है?",opts:["4","5","6","7"],ans:2,exp:"HTML कड़ाई से ठीक छह पदानुक्रमित शीर्षक तत्वों को परिभाषित करता है, जो क्रमिक रूप से `<h1>` से `<h6>` तक गिने जाते हैं। `<h1>` सबसे प्रमुख, शीर्ष-स्तरीय अनुभाग को परिभाषित करता है, जबकि `<h6>` सबसे छोटे, निम्नतम-स्तर के उपखंड को परिभाषित करता है। पहुंच स्क्रीन पाठकों (screen readers) के लिए इन टैगों का उचित क्रमिक उपयोग आवश्यक है।"}},
{type:"mcq",diff:"easy",en:{q:"Which exact syntax is used to insert a hidden comment into HTML code?",opts:["// This is a comment //","/* This is a comment */","<!-- This is a comment -->","<comment> This is a comment </comment>"],ans:2,exp:"HTML comments are structurally wrapped within ``. Any text or code placed between these strict delimiters is entirely ignored by the web browser's rendering engine and will not appear on the screen. Comments are crucial for leaving developer notes or temporarily disabling code blocks."},hi:{q:"HTML कोड में छिपी हुई टिप्पणी (comment) डालने के लिए किस सटीक सिंटैक्स का उपयोग किया जाता है?",opts:["// This is a comment //","/* This is a comment */","<!-- This is a comment -->","<comment> This is a comment </comment>"],ans:2,exp:"HTML टिप्पणियाँ संरचनात्मक रूप से `` के भीतर लिपटी हुई हैं। इन सख्त सीमांककों के बीच रखा गया कोई भी पाठ या कोड वेब ब्राउज़र के रेंडरिंग इंजन द्वारा पूरी तरह से अनदेखा कर दिया जाता है और स्क्रीन पर दिखाई नहीं देगा। डेवलपर नोट्स छोड़ने या कोड ब्लॉक को अक्षम करने के लिए टिप्पणियाँ महत्वपूर्ण हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the correct syntax for writing a comment inside a CSS file?",opts:["// Comment //","","/* Comment */","** Comment **"],ans:2,exp:"Unlike HTML, CSS utilizes the C-style block comment syntax. A CSS comment is initiated with a forward slash and asterisk `/*` and formally terminated with an asterisk and forward slash `*/`. It can span across multiple lines and is completely ignored by the CSS parser."},hi:{q:"CSS फ़ाइल के अंदर टिप्पणी (comment) लिखने का सही सिंटैक्स क्या है?",opts:["// Comment //","","/* Comment */","** Comment **"],ans:2,exp:"HTML के विपरीत, CSS सी-शैली ब्लॉक टिप्पणी सिंटैक्स का उपयोग करता है। एक CSS टिप्पणी एक फॉरवर्ड स्लैश और तारांकन `/*` के साथ शुरू की जाती है और औपचारिक रूप से तारांकन और फॉरवर्ड स्लैश `*/` के साथ समाप्त की जाती है। यह कई पंक्तियों में फैल सकता है और सीएसएस पार्सर द्वारा पूरी तरह से अनदेखा कर दिया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag is required to create a numbered list (Ordered List)?",opts:["<ul>","<list>","<ol>","<li>"],ans:2,exp:"The `<ol>` tag stands for Ordered List. It is specifically designed to create a list where the exact sequential order of items is important. By default, browsers automatically render `<ol>` items with numerical digits (1, 2, 3...), though attributes can change it to roman numerals or alphabetical letters."},hi:{q:"नंबर वाली सूची (ऑर्डर्ड लिस्ट) बनाने के लिए किस टैग की आवश्यकता होती है?",opts:["<ul>","<list>","<ol>","<li>"],ans:2,exp:"`<ol>` टैग का अर्थ ऑर्डर्ड लिस्ट है। यह विशेष रूप से एक सूची बनाने के लिए डिज़ाइन किया गया है जहाँ वस्तुओं का सटीक क्रमिक क्रम महत्वपूर्ण है। डिफ़ॉल्ट रूप से, ब्राउज़र स्वचालित रूप से संख्यात्मक अंकों (1, 2, 3 ...) के साथ `<ol>` आइटम प्रस्तुत करते हैं, हालांकि विशेषताएँ इसे रोमन अंकों या वर्णमाला के अक्षरों में बदल सकती हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag creates a bulleted list (Unordered List)?",opts:["<ol>","<ul>","<bl>","<li>"],ans:1,exp:"The `<ul>` tag establishes an Unordered List. It is used when the specific sequence of the listed items has no semantic importance (like a grocery list). Browsers natively render the items within a `<ul>` with solid black bullet points, which can be modified using CSS `list-style-type`."},hi:{q:"कौन सा टैग बुलेटेड सूची (अनऑर्डर्ड लिस्ट) बनाता है?",opts:["<ol>","<ul>","<bl>","<li>"],ans:1,exp:"`<ul>` टैग एक अनऑर्डर्ड लिस्ट स्थापित करता है। इसका उपयोग तब किया जाता है जब सूचीबद्ध वस्तुओं के विशिष्ट अनुक्रम का कोई अर्थ संबंधी महत्व नहीं होता है (जैसे किराने की सूची)। ब्राउज़र मूल रूप से ठोस काले बुलेट बिंदुओं के साथ `<ul>` के भीतर आइटम प्रस्तुत करते हैं, जिन्हें CSS `list-style-type` का उपयोग करके संशोधित किया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which tag must be nested inside `<ol>` or `<ul>` to define individual items in the list?",opts:["<item>","<lst>","<li>","<list-item>"],ans:2,exp:"The `<li>` (List Item) tag is used exclusively inside the parent `<ol>` or `<ul>` container tags. It explicitly defines each individual bullet point or numbered entry. Attempting to place raw text directly inside a `<ul>` without wrapping it in an `<li>` violates HTML specification rules."},hi:{q:"सूची में व्यक्तिगत आइटम को परिभाषित करने के लिए किस टैग को `<ol>` या `<ul>` के अंदर नेस्ट किया जाना चाहिए?",opts:["<item>","<lst>","<li>","<list-item>"],ans:2,exp:"`<li>` (सूची आइटम) टैग का उपयोग विशेष रूप से मूल `<ol>` या `<ul>` कंटेनर टैग के अंदर किया जाता है। यह स्पष्ट रूप से प्रत्येक व्यक्तिगत बुलेट बिंदु या क्रमांकित प्रविष्टि को परिभाषित करता है। `<li>` में लपेटे बिना सीधे `<ul>` के अंदर कच्चे पाठ को रखने का प्रयास HTML विनिर्देश नियमों का उल्लंघन करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which HTML tag is specifically engineered to embed an image onto a webpage?",opts:["<picture>","<img>","<image>","<src>"],ans:1,exp:"The `<img>` tag is the standard void element used to inject graphical image files (.jpg, .png, .gif) into the browser display. Because it is a void element, it does not have a closing tag. It strictly relies on the `src` attribute to locate the image file on the server."},hi:{q:"वेबपेज पर छवि (image) एम्बेड करने के लिए विशेष रूप से किस HTML टैग को इंजीनियर किया गया है?",opts:["<picture>","<img>","<image>","<src>"],ans:1,exp:"`<img>` टैग ब्राउज़र डिस्प्ले में ग्राफिकल इमेज फ़ाइलों (.jpg, .png, .gif) को इंजेक्ट करने के लिए उपयोग किया जाने वाला मानक शून्य (void) तत्व है। चूँकि यह एक शून्य तत्व है, इसलिए इसमें कोई क्लोजिंग टैग नहीं है। यह सर्वर पर छवि फ़ाइल का पता लगाने के लिए सख्ती से `src` विशेषता पर निर्भर करता है।"}},
{type:"mcq",diff:"easy",en:{q:"By default, which layout behavior does the `<div>` tag exhibit?",opts:["It behaves as a block-level element, taking up the full available width and starting on a new line","It behaves as an inline element, sitting side-by-side with text","It is completely invisible and takes up zero space","It floats to the right side of the screen"],ans:0,exp:"The `<div>` (Division) tag is the ultimate generic block-level container in HTML. By structural default, it physically consumes 100% of its parent's width, forcing a hard line break before and after itself. It is heavily utilized to group elements together for structural CSS styling and grid layouts."},hi:{q:"डिफ़ॉल्ट रूप से, `<div>` टैग किस लेआउट व्यवहार को प्रदर्शित करता है?",opts:["यह एक ब्लॉक-स्तरीय तत्व के रूप में व्यवहार करता है, पूरी उपलब्ध चौड़ाई लेता है और एक नई लाइन पर शुरू होता है","यह एक इनलाइन तत्व के रूप में व्यवहार करता है, पाठ के साथ कंधे से कंधा मिलाकर बैठता है","यह पूरी तरह से अदृश्य है और शून्य स्थान लेता है","यह स्क्रीन के दाईं ओर तैरता है"],ans:0,exp:"`<div>` (डिवीजन) टैग HTML में अंतिम जेनेरिक ब्लॉक-लेवल कंटेनर है। संरचनात्मक डिफ़ॉल्ट रूप से, यह भौतिक रूप से अपने माता-पिता की चौड़ाई का 100% उपभोग करता है, जिससे अपने पहले और बाद में एक हार्ड लाइन ब्रेक मजबूर होता है। संरचनात्मक सीएसएस स्टाइलिंग और ग्रिड लेआउट के लिए तत्वों को एक साथ समूहित करने के लिए इसका भारी उपयोग किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"By default, which layout behavior does the `<span>` tag exhibit?",opts:["It forces a line break","It behaves as a block-level element","It behaves as an inline element, only taking up as much width as its content without forcing a new line","It creates a table row"],ans:2,exp:"The `<span>` tag is the fundamental generic inline container. Unlike a `<div>`, it does not disrupt the natural document flow. It strictly wraps around content and occupies exactly the width of the text it contains. It is typically used to target a specific word inside a paragraph to apply isolated CSS color or styling."},hi:{q:"डिफ़ॉल्ट रूप से, `<span>` टैग किस लेआउट व्यवहार को प्रदर्शित करता है?",opts:["यह लाइन ब्रेक को मजबूर करता है","यह ब्लॉक-स्तरीय तत्व के रूप में व्यवहार करता है","यह एक इनलाइन तत्व के रूप में व्यवहार करता है, बिना नई लाइन बनाए केवल उतनी ही चौड़ाई लेता है जितनी इसकी सामग्री है","यह एक टेबल पंक्ति बनाता है"],ans:2,exp:"`<span>` टैग मूलभूत जेनेरिक इनलाइन कंटेनर है। `<div>` के विपरीत, यह प्राकृतिक दस्तावेज़ प्रवाह को बाधित नहीं करता है। यह कड़ाई से सामग्री के चारों ओर लपेटता है और इसमें मौजूद पाठ की चौड़ाई पर ठीक से कब्जा कर लेता है। इसका उपयोग आमतौर पर अलग-अलग सीएसएस रंग या स्टाइल लागू करने के लिए पैराग्राफ के अंदर एक विशिष्ट शब्द को लक्षित करने के लिए किया जाता है।"}},
{type:"tf",diff:"easy",en:{q:"HTML is considered a fully functional programming language capable of complex mathematical calculations and logic loops.",opts:["True","False"],ans:1,exp:"False. HTML is strictly a 'Markup Language', not a programming language. It is utterly incapable of performing logic, arithmetic, variables, or conditional IF/THEN loops. Its sole capability is to structure and format document content using descriptive tags. Logic is handled by JavaScript."},hi:{q:"HTML को एक पूरी तरह कार्यात्मक प्रोग्रामिंग भाषा माना जाता है जो जटिल गणितीय गणना और तर्क लूप (logic loops) में सक्षम है।",opts:["सही","गलत"],ans:1,exp:"गलत। HTML सख्ती से एक 'मार्कअप लैंग्वेज' है, प्रोग्रामिंग लैंग्वेज नहीं। यह तर्क, अंकगणित, चर (variables), या सशर्त IF/THEN लूप करने में पूरी तरह से असमर्थ है। इसकी एकमात्र क्षमता वर्णनात्मक टैग का उपयोग करके दस्तावेज़ सामग्री को संरचना और प्रारूपित करना है। तर्क जावास्क्रिप्ट द्वारा नियंत्रित किया जाता है।"}},
{type:"tf",diff:"easy",en:{q:"CSS code can only be written inside an external file and linked to the HTML document.",opts:["True","False"],ans:1,exp:"False. CSS can be implemented in three distinct ways: External (linked via a separate .css file), Internal (written inside `<style>` tags within the HTML `<head>`), and Inline (applied directly to a specific tag using the `style=\"\"` attribute)."},hi:{q:"CSS कोड केवल एक बाहरी फ़ाइल (external file) के अंदर लिखा जा सकता है और HTML दस्तावेज़ से जोड़ा जा सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। CSS को तीन अलग-अलग तरीकों से लागू किया जा सकता है: बाहरी (एक अलग .css फ़ाइल के माध्यम से जुड़ा हुआ), आंतरिक (HTML `<head>` के भीतर `<style>` टैग के अंदर लिखा गया), और इनलाइन (सीधे `style=\"\"` विशेषता का उपयोग करके एक विशिष्ट टैग पर लागू)।"}},
{type:"tf",diff:"easy",en:{q:"The `<title>` tag must be placed strictly inside the `<head>` section of an HTML document.",opts:["True","False"],ans:0,exp:"True. The `<title>` tag provides the precise text string that appears on the browser's upper window tab and is used by search engines. Because it represents metadata and is not visible payload content on the webpage body itself, it must reside exclusively within the `<head>` block."},hi:{q:"`<title>` टैग को HTML दस्तावेज़ के `<head>` अनुभाग के अंदर कड़ाई से रखा जाना चाहिए।",opts:["सही","गलत"],ans:0,exp:"सही। `<title>` टैग सटीक टेक्स्ट स्ट्रिंग प्रदान करता है जो ब्राउज़र के ऊपरी विंडो टैब पर दिखाई देता है और खोज इंजन द्वारा उपयोग किया जाता है। चूंकि यह मेटाडेटा का प्रतिनिधित्व करता है और वेबपेज बॉडी पर दृश्यमान पेलोड सामग्री नहीं है, इसलिए इसे विशेष रूप से `<head>` ब्लॉक के भीतर रहना चाहिए।"}},
{type:"tf",diff:"easy",en:{q:"Excessive spaces and blank lines (white space) typed into the HTML code editor will be automatically displayed as huge gaps on the live webpage.",opts:["True","False"],ans:1,exp:"False. HTML inherently uses a process called 'white space collapsing'. No matter if a developer hits the spacebar 50 times or presses Enter 10 times in the raw code editor, the browser's rendering engine aggressively collapses all consecutive blank spaces into one single space on the live screen. `<br>` or CSS is required for spacing."},hi:{q:"HTML कोड एडिटर में टाइप किए गए अत्यधिक स्पेस और खाली लाइनें (सफेद स्थान) लाइव वेबपेज पर बड़े गैप के रूप में स्वचालित रूप से प्रदर्शित होंगे।",opts:["सही","गलत"],ans:1,exp:"गलत। HTML स्वाभाविक रूप से 'व्हाइट स्पेस कोलैप्सिंग' नामक प्रक्रिया का उपयोग करता है। कोई फर्क नहीं पड़ता कि कोई डेवलपर कच्चे कोड संपादक में 50 बार स्पेसबार हिट करता है या 10 बार एंटर दबाता है, ब्राउज़र का रेंडरिंग इंजन आक्रामक रूप से लाइव स्क्रीन पर एक ही स्थान पर सभी लगातार रिक्त स्थान को ढह देता है। रिक्ति के लिए `<br>` या CSS आवश्यक है।"}},
{type:"tf",diff:"easy",en:{q:"Every single HTML tag must absolutely have a corresponding closing tag to function.",opts:["True","False"],ans:1,exp:"False. While container elements like `<h1>` and `<p>` require closing tags, HTML incorporates 'Void Elements' (or empty elements) that cannot contain text content and strictly do not have closing tags. Common void elements include `<br>`, `<hr>`, `<img>`, and `<input>`."},hi:{q:"प्रत्येक HTML टैग में कार्य करने के लिए संबंधित क्लोजिंग टैग का होना बिल्कुल आवश्यक है।",opts:["सही","गलत"],ans:1,exp:"गलत। जबकि `<h1>` और `<p>` जैसे कंटेनर तत्वों को क्लोजिंग टैग की आवश्यकता होती है, HTML में 'शून्य तत्व' (Void Elements) शामिल होते हैं जिनमें पाठ सामग्री नहीं हो सकती है और सख्ती से क्लोजिंग टैग नहीं होते हैं। सामान्य शून्य तत्वों में `<br>`, `<hr>`, `<img>` और `<input>` शामिल हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In CSS, which specific symbol prefix is used to target and style an HTML 'Class'?",opts:["# (Hash)","* (Asterisk)",". (Period / Dot)","@ (At symbol)"],ans:2,exp:"The Period (.) is the structural syntax used in CSS to define a Class selector (e.g., `.highlight { color: yellow; }`). Classes are incredibly powerful because a single class rule can be simultaneously applied to dozens of different HTML elements across the page using the `class=\"highlight\"` attribute."},hi:{q:"CSS में, HTML 'क्लास' (Class) को लक्षित करने और स्टाइल करने के लिए किस विशिष्ट प्रतीक उपसर्ग का उपयोग किया जाता है?",opts:["# (हैश)","* (तारांकन / Asterisk)",". (बिंदु / Dot)","@ (एट प्रतीक)"],ans:2,exp:"बिंदु (.) CSS में क्लास चयनकर्ता (उदा., `.highlight { color: yellow; }`) को परिभाषित करने के लिए उपयोग किया जाने वाला संरचनात्मक सिंटैक्स है। कक्षाएं अविश्वसनीय रूप से शक्तिशाली हैं क्योंकि एक वर्ग नियम को `class=\"highlight\"` विशेषता का उपयोग करके पृष्ठ के दर्जनों विभिन्न HTML तत्वों पर एक साथ लागू किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which specific symbol prefix dictates an 'ID' selector in CSS?",opts:[". (Period)","& (Ampersand)","# (Hash)","$ (Dollar sign)"],ans:2,exp:"The Hash (#) symbol strictly designates an ID selector in a CSS stylesheet (e.g., `#main-header { font-size: 24px; }`). By strict HTML standards, an ID is absolutely unique; a specific ID name can only be assigned to exactly one single element on a given webpage, making it a highly specific targeting tool."},hi:{q:"CSS में 'ID' चयनकर्ता को कौन सा विशिष्ट प्रतीक उपसर्ग निर्देशित करता है?",opts:[". (बिंदु)","& (एम्परसेंड)","# (हैश)","$ (डॉलर चिह्न)"],ans:2,exp:"हैश (#) प्रतीक सख्ती से CSS स्टाइलशीट (उदा., `#main-header { font-size: 24px; }`) में ID चयनकर्ता को नामित करता है। सख्त HTML मानकों के अनुसार, एक ID बिल्कुल अद्वितीय है; एक विशिष्ट ID नाम केवल दिए गए वेबपेज पर ठीक एक ही तत्व को सौंपा जा सकता है, जिससे यह एक अत्यधिक विशिष्ट लक्ष्यीकरण उपकरण बन जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which required attribute inside the `<a>` (Anchor) tag dictates the actual URL destination the hyperlink will navigate to?",opts:["src","link","target","href"],ans:3,exp:"The `href` (Hypertext Reference) attribute is the critical engine of the anchor `<a>` tag. Without `href`, the tag is useless. It explicitly contains the URL path (either an absolute web address like https://google.com or a relative local file path) that the browser requests when the user clicks the link."},hi:{q:"`<a>` (एंकर) टैग के अंदर कौन सा आवश्यक विशेषता (attribute) वास्तविक URL गंतव्य को निर्धारित करता है जिस पर हाइपरलिंक नेविगेट करेगा?",opts:["src","link","target","href"],ans:3,exp:"`href` (हाइपरटेक्स्ट रेफरेंस) एट्रिब्यूट एंकर `<a>` टैग का महत्वपूर्ण इंजन है। `href` के बिना, टैग बेकार है। इसमें स्पष्ट रूप से URL पथ (या तो एक पूर्ण वेब पता जैसे https://google.com या एक सापेक्ष स्थानीय फ़ाइल पथ) शामिल है जिसे उपयोगकर्ता लिंक पर क्लिक करने पर ब्राउज़र अनुरोध करता है।"}},
{type:"mcq",diff:"medium",en:{q:"If an `<img>` fails to load due to a broken link, which attribute provides backup text to describe the image?",opts:["title","desc","alt","fallback"],ans:2,exp:"The `alt` (Alternate Text) attribute serves two vital purposes. Firstly, if the image file breaks or the server fails, the browser displays this text instead to maintain context. Secondly, it is absolutely essential for accessibility, as screen reading software reads the `alt` text aloud to visually impaired users so they understand the image content."},hi:{q:"यदि टूटे हुए लिंक के कारण `<img>` लोड होने में विफल रहता है, तो कौन सी विशेषता (attribute) छवि का वर्णन करने के लिए बैकअप टेक्स्ट प्रदान करती है?",opts:["title","desc","alt","fallback"],ans:2,exp:"`alt` (वैकल्पिक पाठ) विशेषता दो महत्वपूर्ण उद्देश्यों को पूरा करती है। सबसे पहले, यदि छवि फ़ाइल टूट जाती है या सर्वर विफल हो जाता है, तो ब्राउज़र संदर्भ बनाए रखने के लिए इस पाठ को प्रदर्शित करता है। दूसरा, यह पहुंच के लिए बिल्कुल आवश्यक है, क्योंकि स्क्रीन पढ़ने वाला सॉफ्टवेयर नेत्रहीन उपयोगकर्ताओं को `alt` पाठ जोर से पढ़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"When constructing a table in HTML, which tag physically defines a new horizontal Row?",opts:["<td>","<tr>","<table>","<th>"],ans:1,exp:"The `<tr>` (Table Row) tag physically constructs horizontal rows inside an HTML table structure. Every table must have rows declared first. Inside each `<tr>` block, the developer then nests `<td>` (data cells) or `<th>` (header cells) to divide that specific horizontal row into vertical columns."},hi:{q:"HTML में तालिका बनाते समय, कौन सा टैग भौतिक रूप से एक नई क्षैतिज पंक्ति (horizontal Row) को परिभाषित करता है?",opts:["<td>","<tr>","<table>","<th>"],ans:1,exp:"`<tr>` (टेबल रो) टैग भौतिक रूप से एक HTML टेबल संरचना के अंदर क्षैतिज पंक्तियों का निर्माण करता है। प्रत्येक तालिका में पहले पंक्तियाँ घोषित की जानी चाहिए। प्रत्येक `<tr>` ब्लॉक के अंदर, डेवलपर फिर उस विशिष्ट क्षैतिज पंक्ति को ऊर्ध्वाधर स्तंभों में विभाजित करने के लिए `<td>` (डेटा सेल) या `<th>` (हेडर सेल) को घोंसला बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which tag defines a standard data cell (a column block) inside a table row?",opts:["<tc>","<cell>","<th>","<td>"],ans:3,exp:"The `<td>` (Table Data) tag is the core container for table content. Placed exclusively inside a `<tr>` element, it constructs a single cell. By default, content inside a `<td>` is left-aligned and has a normal font weight. If three `<td>` tags are placed in one `<tr>`, the row will have three columns."},hi:{q:"कौन सा टैग तालिका पंक्ति (table row) के अंदर एक मानक डेटा सेल (एक कॉलम ब्लॉक) को परिभाषित करता है?",opts:["<tc>","<cell>","<th>","<td>"],ans:3,exp:"`<td>` (टेबल डेटा) टैग टेबल सामग्री के लिए मुख्य कंटेनर है। विशेष रूप से `<tr>` तत्व के अंदर रखा गया, यह एकल सेल बनाता है। डिफ़ॉल्ट रूप से, `<td>` के अंदर की सामग्री बाएं-संरेखित होती है और इसका फ़ॉन्ट वजन सामान्य होता है। यदि तीन `<td>` टैग एक `<tr>` में रखे गए हैं, तो पंक्ति में तीन कॉलम होंगे।"}},
{type:"mcq",diff:"medium",en:{q:"To define a table cell as a prominent Header (usually bold and centered), which tag replaces `<td>`?",opts:["<head>","<th>","<theader>","<title>"],ans:1,exp:"The `<th>` (Table Header) tag is used to distinctly mark a cell as a header for a column or row. Web browsers automatically apply specialized default CSS to `<th>` elements, making the text bold and perfectly centering it horizontally within the cell to visually separate it from standard `<td>` data."},hi:{q:"एक तालिका सेल (table cell) को प्रमुख हेडर (आमतौर पर बोल्ड और केंद्रित) के रूप में परिभाषित करने के लिए, कौन सा टैग `<td>` को बदल देता है?",opts:["<head>","<th>","<theader>","<title>"],ans:1,exp:"`<th>` (टेबल हेडर) टैग का उपयोग एक सेल को कॉलम या पंक्ति के लिए हेडर के रूप में विशिष्ट रूप से चिह्नित करने के लिए किया जाता है। वेब ब्राउज़र स्वचालित रूप से `<th>` तत्वों पर विशेष डिफ़ॉल्ट CSS लागू करते हैं, जिससे टेक्स्ट बोल्ड हो जाता है और इसे मानक `<td>` डेटा से अलग करने के लिए सेल के भीतर क्षैतिज रूप से केंद्रित कर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"In the CSS Box Model, which property dictates the transparent spacing INSIDE the border, directly pushing the content inward?",opts:["margin","border","padding","spacing"],ans:2,exp:"The CSS Box Model wraps every HTML element. 'Padding' is the innermost layer of spacing. It clears an area tightly around the content, residing physically inside the element's border. Increasing padding physically expands the total size of the element's box while pushing the text deeper inside."},hi:{q:"सीएसएस बॉक्स मॉडल (CSS Box Model) में, कौन सी संपत्ति सीमा (border) के अंदर पारदर्शी रिक्ति को निर्देशित करती है, सीधे सामग्री को अंदर की ओर धकेलती है?",opts:["मार्जिन (margin)","बॉर्डर (border)","पैडिंग (padding)","स्पेसिंग (spacing)"],ans:2,exp:"CSS बॉक्स मॉडल प्रत्येक HTML तत्व को लपेटता है। 'पैडिंग' रिक्ति की सबसे भीतरी परत है। यह सामग्री के चारों ओर एक क्षेत्र को साफ करता है, जो भौतिक रूप से तत्व की सीमा के अंदर रहता है। पैडिंग बढ़ाने से पाठ को गहराई तक धकेलते हुए तत्व के बॉक्स का कुल आकार भौतिक रूप से बढ़ जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"In the CSS Box Model, which property creates transparent whitespace OUTSIDE the border, pushing away neighboring elements?",opts:["padding","margin","outline","border"],ans:1,exp:"'Margin' is the outermost layer of the CSS Box Model. It creates a completely transparent buffer zone strictly outside the element's defined border. Applying a large margin physically pushes neighboring HTML elements further away, effectively controlling the white space layout of the entire page structure."},hi:{q:"सीएसएस बॉक्स मॉडल में, कौन सी संपत्ति सीमा (border) के बाहर पारदर्शी व्हाट्सएप बनाती है, जिससे पड़ोसी तत्वों को दूर धकेल दिया जाता है?",opts:["पैडिंग (padding)","मार्जिन (margin)","आउटलाइन (outline)","बॉर्डर (border)"],ans:1,exp:"'मार्जिन' सीएसएस बॉक्स मॉडल की सबसे बाहरी परत है। यह तत्व की परिभाषित सीमा के कड़ाई से बाहर पूरी तरह से पारदर्शी बफर ज़ोन बनाता है। एक बड़ा मार्जिन लागू करना भौतिक रूप से पड़ोसी HTML तत्वों को दूर धकेलता है, जो पूरे पृष्ठ संरचना के सफेद अंतरिक्ष लेआउट को प्रभावी ढंग से नियंत्रित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which HTML attribute is explicitly used to inject Inline CSS directly into a specific tag?",opts:["class","id","style","format"],ans:2,exp:"The `style` attribute allows developers to apply 'Inline CSS'. By writing `<h1 style=\"color:blue;\">`, the CSS rule is injected directly into the HTML tag. While it possesses the highest specificity (overriding external stylesheets), excessive use of inline styles creates bloated, unmaintainable HTML code."},hi:{q:"कौन सी HTML विशेषता (attribute) स्पष्ट रूप से विशिष्ट टैग में इनलाइन सीएसएस (Inline CSS) को इंजेक्ट करने के लिए उपयोग की जाती है?",opts:["class","id","style","format"],ans:2,exp:"`style` विशेषता डेवलपर्स को 'इनलाइन CSS' लागू करने की अनुमति देती है। `<h1 style=\"color:blue;\">` लिखकर, CSS नियम सीधे HTML टैग में इंजेक्ट किया जाता है। यद्यपि इसमें उच्चतम विशिष्टता है, इनलाइन शैलियों के अत्यधिक उपयोग से फूला हुआ, अप्राप्य HTML कोड बनता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which CSS property is responsible for horizontally aligning text to the center, right, or justify?",opts:["text-position","align-content","text-align","vertical-align"],ans:2,exp:"The `text-align` property dictates the horizontal alignment of inline content (like text or images) inside a block-level container. Standard values include `left` (default), `right`, `center`, and `justify` (which stretches text to perfectly touch both the left and right borders of the container)."},hi:{q:"कौन सी CSS संपत्ति पाठ को क्षैतिज रूप से केंद्र (center), दाएं (right), या उचित (justify) में संरेखित करने के लिए जिम्मेदार है?",opts:["text-position","align-content","text-align","vertical-align"],ans:2,exp:"`text-align` संपत्ति एक ब्लॉक-स्तरीय कंटेनर के अंदर इनलाइन सामग्री (जैसे टेक्स्ट या चित्र) के क्षैतिज संरेखण को निर्देशित करती है। मानक मानों में 'बाएं' (left), 'दाएं' (right), 'केंद्र' (center), और 'औचित्य' (justify) शामिल हैं।"}},
{type:"mcq",diff:"medium",en:{q:"To create a secure input field where the typed characters are masked as dots or asterisks, which type attribute is used?",opts:["type=\"hidden\"","type=\"mask\"","type=\"secure\"","type=\"password\""],ans:3,exp:"Setting an HTML input to `<input type=\"password\">` triggers a critical security behavior in the browser. As the user types, the rendering engine automatically masks the characters with black dots or asterisks visually on the screen, preventing 'shoulder-surfing' attacks while the user types sensitive credentials."},hi:{q:"एक सुरक्षित इनपुट फ़ील्ड बनाने के लिए जहां टाइप किए गए वर्णों को डॉट्स या तारांकन के रूप में मुखौटा (masked) किया जाता है, किस प्रकार की विशेषता (type attribute) का उपयोग किया जाता है?",opts:["type=\"hidden\"","type=\"mask\"","type=\"secure\"","type=\"password\""],ans:3,exp:"HTML इनपुट को `<input type=\"password\">` पर सेट करने से ब्राउज़र में एक महत्वपूर्ण सुरक्षा व्यवहार ट्रिगर होता है। जैसे ही उपयोगकर्ता टाइप करता है, रेंडरिंग इंजन स्वचालित रूप से स्क्रीन पर वर्णों को काले डॉट्स या तारांकन के साथ मुखौटा करता है, संवेदनशील क्रेडेंशियल्स टाइप करते समय हमलों को रोकता है।"}},
{type:"mcq",diff:"medium",en:{q:"In an HTML form, which input type enforces mutual exclusivity, allowing the user to select only ONE option from a grouped list?",opts:["type=\"checkbox\"","type=\"radio\"","type=\"select\"","type=\"button\""],ans:1,exp:"The `<input type=\"radio\">` creates a radio button. It is fundamentally engineered for mutual exclusivity. If multiple radio buttons share the exact same `name` attribute in the HTML code, the browser logically links them; clicking one option instantly deselects any previously chosen option in that group."},hi:{q:"HTML फ़ॉर्म में, कौन सा इनपुट प्रकार पारस्परिक विशिष्टता को लागू करता है, जिससे उपयोगकर्ता को समूहीकृत सूची से केवल एक (ONE) विकल्प चुनने की अनुमति मिलती है?",opts:["type=\"checkbox\"","type=\"radio\"","type=\"select\"","type=\"button\""],ans:1,exp:"`<input type=\"radio\">` एक रेडियो बटन बनाता है। यह मूल रूप से पारस्परिक विशिष्टता के लिए इंजीनियर है। यदि कई रेडियो बटन HTML कोड में समान `name` विशेषता साझा करते हैं, तो ब्राउज़र तार्किक रूप से उन्हें जोड़ता है; एक विकल्प पर क्लिक करने से उस समूह में पहले से चुना गया कोई भी विकल्प तुरंत अचयनित हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which form input type allows a user to select multiple options simultaneously from a checklist?",opts:["type=\"radio\"","type=\"checkbox\"","type=\"text\"","type=\"multiple\""],ans:1,exp:"The `<input type=\"checkbox\">` element provides a small square box that acts as an independent toggle switch (checked or unchecked). Unlike radio buttons, checkboxes operate completely independently. A user can legitimately check zero, one, or every single checkbox presented in a form group."},hi:{q:"कौन सा फॉर्म इनपुट प्रकार उपयोगकर्ता को चेकलिस्ट से एक साथ कई विकल्पों का चयन करने की अनुमति देता है?",opts:["type=\"radio\"","type=\"checkbox\"","type=\"text\"","type=\"multiple\""],ans:1,exp:"`<input type=\"checkbox\">` तत्व एक छोटा वर्गाकार बॉक्स प्रदान करता है जो एक स्वतंत्र टॉगल स्विच (जांचा गया या अचयनित) के रूप में कार्य करता है। रेडियो बटन के विपरीत, चेकबॉक्स पूरी तरह से स्वतंत्र रूप से काम करते हैं। उपयोगकर्ता किसी फॉर्म समूह में शून्य, एक या हर एक चेकबॉक्स की जांच कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which required `<form>` attribute specifies the exact backend server URL where the collected form data will be sent upon submission?",opts:["method","src","action","target"],ans:2,exp:"The `action` attribute dictates the exact destination endpoint for the form payload. When a user clicks 'Submit', the browser packages the input data and strictly transmits it to the URL declared in the `action` attribute (e.g., `<form action=\"/submit_login.php\">`) for backend server processing."},hi:{q:"कौन सा आवश्यक `<form>` विशेषता (attribute) सटीक बैकएंड सर्वर URL निर्दिष्ट करती है जहां सबमिट करने पर एकत्रित फ़ॉर्म डेटा भेजा जाएगा?",opts:["method","src","action","target"],ans:2,exp:"`action` विशेषता फॉर्म पेलोड के लिए सटीक गंतव्य समापन बिंदु (destination endpoint) निर्धारित करती है। जब कोई उपयोगकर्ता 'सबमिट' पर क्लिक करता है, तो ब्राउज़र इनपुट डेटा को पैकेज करता है और इसे बैकएंड सर्वर प्रोसेसिंग के लिए `action` एट्रिब्यूट (उदा., `<form action=\"/submit_login.php\">`) में घोषित URL पर सख्ती से प्रसारित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"To securely send sensitive form data (like passwords) hidden in the HTTP request body rather than exposing it in the URL, which method should be used?",opts:["method=\"GET\"","method=\"SEND\"","method=\"SECURE\"","method=\"POST\""],ans:3,exp:"The `method=\"POST\"` attribute is absolutely mandatory for secure data transmission. Unlike the GET method, which appends form data visibly into the URL query string (creating massive security leaks and length limits), POST securely embeds the data directly inside the invisible HTTP request body, making it essential for passwords."},hi:{q:"संवेदनशील फ़ॉर्म डेटा (जैसे पासवर्ड) को URL में उजागर करने के बजाय HTTP अनुरोध निकाय में छिपाकर सुरक्षित रूप से भेजने के लिए, किस विधि का उपयोग किया जाना चाहिए?",opts:["method=\"GET\"","method=\"SEND\"","method=\"SECURE\"","method=\"POST\""],ans:3,exp:"सुरक्षित डेटा ट्रांसमिशन के लिए `method=\"POST\"` विशेषता बिल्कुल अनिवार्य है। GET विधि के विपरीत, जो URL क्वेरी स्ट्रिंग में स्पष्ट रूप से फॉर्म डेटा जोड़ता है, POST डेटा को सीधे अदृश्य HTTP अनुरोध निकाय के अंदर सुरक्षित रूप से एम्बेड करता है, जिससे यह पासवर्ड के लिए आवश्यक हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which HTML tag combination is used to construct a dropdown selection menu in a form?",opts:["<menu> and <item>","<list> and <option>","<select> and <option>","<dropdown> and <li>"],ans:2,exp:"A dropdown menu requires a nested tag structure. The parent `<select>` tag establishes the main dropdown container mechanics. Inside it, multiple `<option>` tags are nested. Each `<option>` tag represents a single clickable choice that expands when the user clicks the select box."},hi:{q:"एक फॉर्म में ड्रॉपडाउन चयन मेनू (dropdown selection menu) के निर्माण के लिए किस HTML टैग संयोजन का उपयोग किया जाता है?",opts:["<menu> और <item>","<list> और <option>","<select> और <option>","<dropdown> और <li>"],ans:2,exp:"ड्रॉपडाउन मेनू को नेस्टेड टैग संरचना की आवश्यकता होती है। मूल `<select>` टैग मुख्य ड्रॉपडाउन कंटेनर यांत्रिकी स्थापित करता है। इसके अंदर कई `<option>` टैग नेस्ट किए गए हैं। प्रत्येक `<option>` टैग एक क्लिक करने योग्य विकल्प का प्रतिनिधित्व करता है जो उपयोगकर्ता द्वारा चयन बॉक्स पर क्लिक करने पर फैलता है।"}},
{type:"mcq",diff:"medium",en:{q:"By default, web browsers apply an underline to all `<a>` hyperlinks. Which CSS property actively removes this visual underline?",opts:["text-style: none;","text-decoration: none;","font-style: clear;","link-decoration: none;"],ans:1,exp:"The `text-decoration` property controls supplemental visual line styling on text (underline, overline, line-through). Setting `text-decoration: none;` on anchor `<a>` tags is a highly common modern design practice to strip away the ugly default blue underline while maintaining the link's click functionality."},hi:{q:"डिफ़ॉल्ट रूप से, वेब ब्राउज़र सभी `<a>` हाइपरलिंक पर एक अंडरलाइन लागू करते हैं। कौन सी CSS प्रॉपर्टी इस विज़ुअल अंडरलाइन को सक्रिय रूप से हटा देती है?",opts:["text-style: none;","text-decoration: none;","font-style: clear;","link-decoration: none;"],ans:1,exp:"`text-decoration` संपत्ति टेक्स्ट (अंडरलाइन, ओवरलाइन, लाइन-थ्रू) पर पूरक विज़ुअल लाइन स्टाइल को नियंत्रित करती है। एंकर `<a>` टैग पर `text-decoration: none;` सेट करना लिंक की क्लिक कार्यक्षमता को बनाए रखते हुए बदसूरत डिफ़ॉल्ट ब्लू अंडरलाइन को दूर करने के लिए एक अत्यधिक सामान्य आधुनिक डिज़ाइन अभ्यास है।"}},
{type:"mcq",diff:"medium",en:{q:"Which CSS property determines the thickness or boldness of text characters?",opts:["font-weight","font-style","text-thickness","font-family"],ans:0,exp:"The `font-weight` CSS property dictates the exact typographic thickness of the characters. It can accept standard string values like `normal` or `bold`, or precise numerical values ranging strictly from 100 (ultra-thin) up to 900 (ultra-black heavy), depending on the loaded font family's capabilities."},hi:{q:"कौन सी CSS संपत्ति (property) टेक्स्ट वर्णों की मोटाई या साहस (boldness) निर्धारित करती है?",opts:["font-weight","font-style","text-thickness","font-family"],ans:0,exp:"`font-weight` CSS संपत्ति वर्णों की सटीक टाइपोग्राफ़िक मोटाई निर्धारित करती है। यह लोड किए गए फ़ॉन्ट परिवार की क्षमताओं के आधार पर `सामान्य` (normal) या `बोल्ड` (bold) जैसे मानक स्ट्रिंग मानों या कड़ाई से 100 (अल्ट्रा-थिन) से 900 (अल्ट्रा-ब्लैक हेवी) तक के सटीक संख्यात्मक मानों को स्वीकार कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"In an HTML table, if you want a single cell to horizontally span across three columns, which attribute is used?",opts:["merge=\"3\"","rowspan=\"3\"","colspan=\"3\"","span=\"3\""],ans:2,exp:"The `colspan` (column span) attribute is placed inside a `<td>` or `<th>` tag. Setting `colspan=\"3\"` commands the browser's rendering engine to stretch that specific cell horizontally, causing it to physically occupy the geometric space of three standard adjoining columns, ideal for wide header banners."},hi:{q:"HTML तालिका में, यदि आप चाहते हैं कि एक सेल क्षैतिज रूप से तीन कॉलम में फैले, तो किस विशेषता (attribute) का उपयोग किया जाता है?",opts:["merge=\"3\"","rowspan=\"3\"","colspan=\"3\"","span=\"3\""],ans:2,exp:"`colspan` विशेषता को `<td>` या `<th>` टैग के अंदर रखा गया है। `colspan=\"3\"` सेट करने से ब्राउज़र का रेंडरिंग इंजन उस विशिष्ट सेल को क्षैतिज रूप से फैलाने का आदेश देता है, जिससे यह भौतिक रूप से तीन मानक आसन्न कॉलम के ज्यामितीय स्थान पर कब्जा कर लेता है, जो विस्तृत हेडर बैनर के लिए आदर्श है।"}},
{type:"mcq",diff:"medium",en:{q:"Conversely, to merge a table cell vertically down across multiple rows, which attribute is required?",opts:["rowspan","vertical-span","colspan","merge-row"],ans:0,exp:"The `rowspan` attribute instructs the browser to stretch a table cell vertically downwards. Writing `<td rowspan=\"2\">` forces the cell to consume the vertical height of two completely separate rows, pushing adjacent cells out of the way. It is vital for structuring complex data tables."},hi:{q:"इसके विपरीत, किसी तालिका सेल को कई पंक्तियों में लंबवत (vertically) रूप से मर्ज करने के लिए, किस विशेषता (attribute) की आवश्यकता होती है?",opts:["rowspan","vertical-span","colspan","merge-row"],ans:0,exp:"`rowspan` विशेषता ब्राउज़र को एक टेबल सेल को लंबवत नीचे की ओर खींचने का निर्देश देती है। `<td rowspan=\"2\">` लिखने से सेल को पूरी तरह से अलग-अलग दो पंक्तियों की ऊर्ध्वाधर ऊंचाई का उपभोग करने के लिए मजबूर किया जाता है, जिससे आसन्न सेल रास्ते से बाहर हो जाते हैं। जटिल डेटा तालिकाओं की संरचना के लिए यह महत्वपूर्ण है।"}},
{type:"mcq",diff:"medium",en:{q:"Which CSS shorthand property allows you to declare the thickness, line style, and color of an element's perimeter all at once?",opts:["outline","border","margin","padding"],ans:1,exp:"The `border` property acts as a highly efficient shorthand in CSS. Instead of writing three separate lines of code (`border-width`, `border-style`, `border-color`), a developer can declare everything in one single concise line, such as `border: 2px solid black;`, which draws a solid black line around the element."},hi:{q:"कौन सी CSS शॉर्टहैंड संपत्ति आपको एक ही बार में एक तत्व की परिधि की मोटाई, रेखा शैली और रंग घोषित करने की अनुमति देती है?",opts:["आउटलाइन (outline)","बॉर्डर (border)","मार्जिन (margin)","पैडिंग (padding)"],ans:1,exp:"`border` संपत्ति CSS में एक अत्यधिक कुशल आशुलिपि (shorthand) के रूप में कार्य करती है। कोड की तीन अलग-अलग पंक्तियों (`border-width`, `border-style`, `border-color`) को लिखने के बजाय, एक डेवलपर एक ही संक्षिप्त रेखा में सब कुछ घोषित कर सकता है, जैसे `border: 2px solid black;`, जो तत्व के चारों ओर एक ठोस काली रेखा खींचता है।"}},
{type:"mcq",diff:"medium",en:{q:"When creating a hyperlink, which `target` attribute value explicitly commands the browser to open the destination URL in a completely new tab or window?",opts:["_self","_parent","_top","_blank"],ans:3,exp:"Adding `target=\"_blank\"` to an `<a>` tag alters the browser's default navigation behavior. Instead of loading the new webpage over the current screen (`_self`), `_blank` forcefully spawns a brand-new browser tab or window, ensuring the user does not lose their place on the original website."},hi:{q:"हाइपरलिंक बनाते समय, कौन सा `target` एट्रिब्यूट मान स्पष्ट रूप से ब्राउज़र को पूरी तरह से नए टैब या विंडो में गंतव्य URL खोलने का आदेश देता है?",opts:["_self","_parent","_top","_blank"],ans:3,exp:"`<a>` टैग में `target=\"_blank\"` जोड़ने से ब्राउज़र का डिफ़ॉल्ट नेविगेशन व्यवहार बदल जाता है। वर्तमान स्क्रीन (`_self`) पर नए वेबपेज को लोड करने के बजाय, `_blank` बलपूर्वक एक नया ब्राउज़र टैब या विंडो बनाता है, यह सुनिश्चित करता है कि उपयोगकर्ता मूल वेबसाइट पर अपना स्थान नहीं खोता है।"}},
{type:"mcq",diff:"medium",en:{q:"In CSS, which specific symbol acts as the 'Universal Selector', applying styles massively to absolutely every single tag on the HTML page?",opts:["#","@","*","&"],ans:2,exp:"The asterisk (*) functions as the Universal Selector in CSS. Writing `* { margin: 0; padding: 0; }` acts as a global reset. The rendering engine recursively targets every single existing HTML element on the DOM tree and violently strips away the browser's default spacing rules, giving the developer a blank slate."},hi:{q:"CSS में, कौन सा विशिष्ट प्रतीक 'यूनिवर्सल चयनकर्ता' (Universal Selector) के रूप में कार्य करता है, जो HTML पृष्ठ पर हर एक टैग पर बड़े पैमाने पर स्टाइल लागू करता है?",opts:["#","@","*","&"],ans:2,exp:"तारांकन (*) CSS में यूनिवर्सल चयनकर्ता के रूप में कार्य करता है। `* { margin: 0; padding: 0; }` लिखना एक वैश्विक रीसेट के रूप में कार्य करता है। रेंडरिंग इंजन डीओएम पेड़ पर मौजूद हर एक एचटीएमएल तत्व को पुनरावर्ती रूप से लक्षित करता है और डेवलपर को एक खाली स्लेट देते हुए ब्राउज़र के डिफ़ॉल्ट रिक्ति नियमों को हटा देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which modern HTML5 semantic tag is strictly designed to wrap major blocks of navigation links (like a website's main menu)?",opts:["<menu>","<section>","<header>","<nav>"],ans:3,exp:"Introduced in HTML5, the `<nav>` tag is a highly semantic structural element. While visually it behaves exactly like a generic `<div>`, it explicitly signals to search engine crawlers and screen readers that the enclosed block of links is the primary navigational menu for the site, greatly boosting accessibility."},hi:{q:"कौन सा आधुनिक HTML5 सिमेंटिक टैग नेविगेशन लिंक (जैसे वेबसाइट का मुख्य मेनू) के प्रमुख ब्लॉकों को लपेटने के लिए सख्ती से डिज़ाइन किया गया है?",opts:["<menu>","<section>","<header>","<nav>"],ans:3,exp:"HTML5 में पेश किया गया, `<nav>` टैग एक अत्यधिक अर्थपूर्ण संरचनात्मक तत्व है। यद्यपि दृश्य रूप से यह एक सामान्य `<div>` की तरह काम करता है, यह स्पष्ट रूप से खोज इंजन क्रॉलर और स्क्रीन पाठकों को संकेत देता है कि लिंक का संलग्न ब्लॉक साइट के लिए प्राथमिक नेविगेशनल मेनू है।"}},
{type:"tf",diff:"medium",en:{q:"In standard CSS, an ID selector (e.g., #header) can legally be applied to 10 different elements on the exact same HTML page.",opts:["True","False"],ans:1,exp:"False. By strict W3C HTML specifications, an ID must be absolutely unique per document. While a Class can be infinitely reused on multiple elements, an ID (like `id=\"header\"`) can only be assigned to one single specific element. Breaking this rule causes JavaScript targeting errors."},hi:{q:"मानक CSS में, एक ID चयनकर्ता (उदा., #header) को कानूनी रूप से उसी HTML पृष्ठ पर 10 विभिन्न तत्वों पर लागू किया जा सकता है।",opts:["सही","गलत"],ans:1,exp:"गलत। सख्त W3C HTML विनिर्देशों के अनुसार, प्रति दस्तावेज़ एक आईडी (ID) बिल्कुल अद्वितीय होनी चाहिए। जबकि एक वर्ग (Class) का उपयोग कई तत्वों पर असीम रूप से किया जा सकता है, एक आईडी (जैसे `id=\"header\"`) केवल एक विशिष्ट तत्व को सौंपी जा सकती है। इस नियम को तोड़ने से जावास्क्रिप्ट लक्ष्यीकरण त्रुटियां होती हैं।"}},
{type:"tf",diff:"medium",en:{q:"In the CSS Box Model, increasing the 'padding' of an element pushes the border outward, expanding the physical size of the element's box.",opts:["True","False"],ans:0,exp:"True. Padding sits mathematically between the content and the border. By default, adding 20px of padding physically expands the element's overall computed width and height footprint by 40px (20px left + 20px right), pushing the outer border boundary further away from the text."},hi:{q:"सीएसएस बॉक्स मॉडल में, किसी तत्व की 'पैडिंग' (padding) बढ़ाने से सीमा (border) बाहर की ओर धकेलती है, जिससे तत्व के बॉक्स का भौतिक आकार बढ़ जाता है।",opts:["सही","गलत"],ans:0,exp:"सही। पैडिंग गणितीय रूप से सामग्री और सीमा के बीच बैठती है। डिफ़ॉल्ट रूप से, पैडिंग का 20px जोड़ना भौतिक रूप से तत्व की समग्र गणना की गई चौड़ाई और ऊंचाई के पदचिह्न को 40px (20px बाएँ + 20px दाएँ) तक विस्तारित करता है, बाहरी सीमा की सीमा को पाठ से दूर धकेलता है।"}},
{type:"tf",diff:"medium",en:{q:"Text written directly inside the `<head>` tag is prominently displayed as a large heading at the top of the browser window.",opts:["True","False"],ans:1,exp:"False. The `<head>` tag is strictly a hidden administrative container for metadata, CSS links, and scripts. Absolutely NO content placed inside the `<head>` (except the `<title>` which goes on the browser tab) is graphically rendered inside the visible webpage area. Visible headings use the `<h1>` tag inside the `<body>`."},hi:{q:"सीधे `<head>` टैग के अंदर लिखा गया पाठ प्रमुख रूप से ब्राउज़र विंडो के शीर्ष पर एक बड़े शीर्षक के रूप में प्रदर्शित होता है।",opts:["सही","गलत"],ans:1,exp:"गलत। `<head>` टैग सख्ती से मेटाडेटा, सीएसएस लिंक और स्क्रिप्ट के लिए एक छिपा हुआ प्रशासनिक कंटेनर है। `<head>` के अंदर रखी गई कोई भी सामग्री (सिवाय `<title>` के जो ब्राउज़र टैब पर जाती है) दृश्यमान वेबपेज क्षेत्र के अंदर ग्राफिक रूप से प्रस्तुत नहीं की जाती है। दृश्य शीर्षकों के लिए `<body>` के अंदर `<h1>` टैग का उपयोग होता है।"}},
{type:"tf",diff:"medium",en:{q:"Applying the CSS rule `margin: 0 auto;` to a block-level element with a defined width perfectly centers it horizontally on the page.",opts:["True","False"],ans:0,exp:"True. This is a classic CSS layout trick. By setting the top/bottom margin to 0, and the left/right margin to `auto`, the browser's rendering engine calculates the exact remaining empty space on the screen and perfectly splits it in half, locking the block element directly into the horizontal center."},hi:{q:"एक परिभाषित चौड़ाई वाले ब्लॉक-स्तरीय तत्व पर CSS नियम `margin: 0 auto;` लागू करने से यह पृष्ठ पर क्षैतिज रूप से (horizontally) पूरी तरह से केंद्रित हो जाता है।",opts:["सही","गलत"],ans:0,exp:"सही। यह एक क्लासिक सीएसएस लेआउट ट्रिक है। ऊपर/नीचे के मार्जिन को 0 पर सेट करके, और बाएँ/दाएँ मार्जिन को `auto` पर सेट करके, ब्राउज़र का रेंडरिंग इंजन स्क्रीन पर शेष खाली स्थान की गणना करता है और इसे पूरी तरह से आधे में विभाजित करता है, ब्लॉक तत्व को सीधे क्षैतिज केंद्र में लॉक करता है।"}},
{type:"tf",diff:"medium",en:{q:"The `alt` attribute in an `<img>` tag is useless unless the image fails to load; it has no impact on Search Engine Optimization (SEO).",opts:["True","False"],ans:1,exp:"False. The `alt` (Alternate Text) attribute is critically analyzed by Google's search engine crawlers to understand the semantic context of an image, massively boosting SEO image ranking. It is also a mandatory legal requirement for web accessibility, allowing screen readers to describe images to blind users."},hi:{q:"`<img>` टैग में `alt` विशेषता तब तक बेकार है जब तक कि छवि लोड होने में विफल न हो; इसका सर्च इंजन ऑप्टिमाइजेशन (SEO) पर कोई प्रभाव नहीं पड़ता है।",opts:["सही","गलत"],ans:1,exp:"गलत। Google के सर्च इंजन क्रॉलर द्वारा किसी छवि के अर्थ संबंधी संदर्भ को समझने के लिए `alt` (वैकल्पिक पाठ) विशेषता का गंभीर रूप से विश्लेषण किया जाता है, जिससे एसईओ छवि रैंकिंग में भारी वृद्धि होती है। यह वेब एक्सेसिबिलिटी के लिए एक अनिवार्य कानूनी आवश्यकता भी है, जो स्क्रीन रीडर्स को अंधे उपयोगकर्ताओं के लिए छवियों का वर्णन करने की अनुमति देती है।"}},
{type:"mcq",diff:"hard",en:{q:"In CSS Specificity hierarchy, which rule takes ultimate precedence and actively overwrites all other standard styling rules?",opts:["ID Selectors (#)","Class Selectors (.)","Inline CSS (style=\"\")","Element Selectors (h1)"],ans:2,exp:"CSS specificity is governed by strict mathematical weighting. Element tags carry 1 point, Classes carry 10 points, and IDs carry 100 points. However, Inline styles coded directly into the HTML tag via the `style` attribute carry 1000 points, mathematically obliterating all external and internal stylesheet rules."},hi:{q:"सीएसएस विशिष्टता (CSS Specificity) पदानुक्रम में, कौन सा नियम अंतिम पूर्वता लेता है और सक्रिय रूप से अन्य सभी मानक स्टाइलिंग नियमों को अधिलेखित (overwrites) करता है?",opts:["आईडी चयनकर्ता (#)","क्लास चयनकर्ता (.)","इनलाइन सीएसएस (style=\"\")","तत्व चयनकर्ता (h1)"],ans:2,exp:"सीएसएस विशिष्टता सख्त गणितीय भार द्वारा नियंत्रित होती है। तत्व टैग में 1 अंक, कक्षाओं में 10 अंक और आईडी में 100 अंक होते हैं। हालाँकि, `style` विशेषता के माध्यम से सीधे HTML टैग में कोड की गई इनलाइन शैलियाँ 1000 अंकों को ले जाती हैं, जो गणितीय रूप से सभी बाहरी और आंतरिक स्टाइलशीट नियमों को मिटा देती हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which CSS Pseudo-class dynamically triggers a style change strictly when the user physically places their mouse pointer over an element without clicking?",opts:[":active",":visited",":focus",":hover"],ans:3,exp:"The `:hover` pseudo-class (e.g., `button:hover { background: red; }`) allows developers to inject interactivity using pure CSS. The browser actively monitors the mouse cursor's X/Y coordinates; the millisecond the cursor physically intersects the element's geometric bounding box, the hover styles are violently applied."},hi:{q:"कौन सा CSS छद्म-वर्ग (Pseudo-class) गतिशील रूप से शैली परिवर्तन को ट्रिगर करता है जब उपयोगकर्ता क्लिक किए बिना किसी तत्व पर अपना माउस पॉइंटर रखता है?",opts:[":active",":visited",":focus",":hover"],ans:3,exp:"`:hover` छद्म वर्ग (उदा., `button:hover { background: red; }`) डेवलपर्स को शुद्ध CSS का उपयोग करके अन्तरक्रियाशीलता इंजेक्ट करने की अनुमति देता है। ब्राउज़र सक्रिय रूप से माउस कर्सर के निर्देशांक की निगरानी करता है; जैसे ही कर्सर भौतिक रूप से तत्व के ज्यामितीय बाउंडिंग बॉक्स को पार करता है, होवर शैलियों को लागू किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which CSS positioning method permanently locks an element's geometric location relative to the browser viewport, making it completely immune to page scrolling?",opts:["position: absolute;","position: fixed;","position: relative;","position: static;"],ans:1,exp:"Setting an element to `position: fixed;` physically detaches it from the normal document flow. Its coordinates (top, bottom, left, right) are mathematically bolted directly to the glass of the browser window (the viewport). No matter how far down the user scrolls, the element remains frozen on the screen."},hi:{q:"कौन सी CSS पोजिशनिंग (positioning) विधि ब्राउज़र व्यूपोर्ट के सापेक्ष किसी तत्व के ज्यामितीय स्थान को स्थायी रूप से लॉक कर देती है, जिससे यह पृष्ठ स्क्रॉलिंग के लिए पूरी तरह से प्रतिरक्षा बन जाता है?",opts:["position: absolute;","position: fixed;","position: relative;","position: static;"],ans:1,exp:"किसी तत्व को `position: fixed;` पर सेट करने से वह भौतिक रूप से सामान्य दस्तावेज़ प्रवाह से अलग हो जाता है। इसके निर्देशांक सीधे ब्राउज़र विंडो (व्यूपोर्ट) के ग्लास पर बोल्ट किए जाते हैं। उपयोगकर्ता कितनी भी दूर नीचे स्क्रॉल करे, तत्व स्क्रीन पर जमा रहता है।"}},
{type:"mcq",diff:"hard",en:{q:"When using `position: absolute;`, what is the element's positioning mathematically calculated relative to?",opts:["The browser window","The exact center of the page","Its nearest ancestor element that has a position property other than 'static'","The bottom of the document flow"],ans:2,exp:"`position: absolute` is highly complex. An absolutely positioned element looks up its DOM tree hierarchy. It anchors its top/left coordinates strictly to the very first parent container it finds that has `position: relative`, `absolute`, or `fixed`. If it finds zero positioned parents, it defaults back to anchoring to the main HTML `<body>`."},hi:{q:"`position: absolute;` का उपयोग करते समय, तत्व की स्थिति गणितीय रूप से किसके सापेक्ष गणना की जाती है?",opts:["ब्राउज़र विंडो","पृष्ठ का सटीक केंद्र","इसका निकटतम पूर्वज तत्व (ancestor element) जिसमें 'static' के अलावा कोई अन्य स्थिति संपत्ति है","दस्तावेज़ प्रवाह का तल (bottom)"],ans:2,exp:"`position: absolute` अत्यधिक जटिल है। यह अपने DOM पेड़ पदानुक्रम को देखता है। यह अपने शीर्ष/बाएँ निर्देशांकों को कड़ाई से पहले मूल कंटेनर में लंगर डालता है जो पाता है कि `position: relative`, `absolute`, या `fixed` है। यदि इसे शून्य-स्थित माता-पिता मिलते हैं, तो यह मुख्य HTML `<body>` में एंकरिंग के लिए वापस डिफ़ॉल्ट हो जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which modern HTML5 tag natively embeds moving video footage directly into the page without requiring clunky third-party plugins like Adobe Flash?",opts:["<media>","<movie>","<video>","<embed>"],ans:2,exp:"Before HTML5, embedding video required heavy, insecure plugins. The modern `<video>` tag natively decodes and plays mp4/webm files via the browser's internal engine. Developers can inject attributes like `controls`, `autoplay`, and `loop` to dictate the player's UI and playback behavior seamlessly."},hi:{q:"कौन सा आधुनिक HTML5 टैग एडोब फ्लैश जैसे क्लंकी थर्ड-पार्टी प्लगइन्स की आवश्यकता के बिना सीधे पृष्ठ में मूविंग वीडियो फुटेज को एम्बेड करता है?",opts:["<media>","<movie>","<video>","<embed>"],ans:2,exp:"HTML5 से पहले, वीडियो एम्बेड करने के लिए भारी प्लगइन्स की आवश्यकता होती थी। आधुनिक `<video>` टैग मूल रूप से ब्राउज़र के आंतरिक इंजन के माध्यम से mp4/webm फ़ाइलों को डिकोड और चलाता है। डेवलपर्स खिलाड़ी के यूआई और प्लेबैक व्यवहार को निर्धारित करने के लिए `controls`, `autoplay`, और `loop` जैसी विशेषताओं को इंजेक्ट कर सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is the absolute critical function of the `<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">` tag inside the `<head>`?",opts:["To enforce a high-resolution font","To command mobile device browsers not to artificially shrink the page, laying the mathematical foundation for Responsive Web Design","To disable horizontal scrolling entirely","To translate the page to English"],ans:1,exp:"Without this specific Viewport meta tag, mobile browsers (like iPhones) will assume the site is an old desktop site and artificially zoom out, shrinking the text to unreadable micro-sizes. This tag forcefully commands the mobile browser to map CSS pixels 1:1 with hardware pixels, activating responsive media queries."},hi:{q:"`<head>` के अंदर `<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">` टैग का पूर्ण महत्वपूर्ण कार्य क्या है?",opts:["एक उच्च-रिज़ॉल्यूशन फ़ॉन्ट लागू करने के लिए","मोबाइल डिवाइस ब्राउज़रों को पृष्ठ को कृत्रिम रूप से सिकोड़ने का आदेश न देने के लिए, रिस्पॉन्सिव वेब डिज़ाइन (Responsive Web Design) की गणितीय नींव रखना","क्षैतिज स्क्रॉलिंग को पूरी तरह से अक्षम करने के लिए","पृष्ठ का अंग्रेजी में अनुवाद करने के लिए"],ans:1,exp:"इस विशिष्ट व्यूपोर्ट मेटा टैग के बिना, मोबाइल ब्राउज़र (आईफोन की तरह) मान लेंगे कि साइट एक पुरानी डेस्कटॉप साइट है और कृत्रिम रूप से ज़ूम आउट कर देगी, जिससे पाठ को अपठनीय सूक्ष्म आकारों में सिकोड़ दिया जाएगा। यह टैग बलपूर्वक मोबाइल ब्राउज़र को हार्डवेयर पिक्सल के साथ 1: 1 सीएसएस पिक्सल को मैप करने का आदेश देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In a complex layout where multiple elements geometrically overlap, which CSS property dictates the strict Z-axis stacking order (which element appears visually on top)?",opts:["layer-index","overlap-priority","stack-order","z-index"],ans:3,exp:"The `z-index` property commands the 3D depth of the page. Elements with a higher numerical `z-index` (e.g., 999) will violently overlap and cover elements with lower values (e.g., 1). Crucially, `z-index` is mathematically ignored by the browser unless the element has its `position` set to relative, absolute, fixed, or sticky."},hi:{q:"एक जटिल लेआउट में जहां कई तत्व ज्यामितीय रूप से ओवरलैप करते हैं, कौन सी CSS संपत्ति सख्त जेड-अक्ष स्टैकिंग ऑर्डर (Z-axis stacking order) (कौन सा तत्व शीर्ष पर दृष्टिगत रूप से दिखाई देता है) को निर्देशित करती है?",opts:["layer-index","overlap-priority","stack-order","z-index"],ans:3,exp:"`z-index` संपत्ति पृष्ठ की 3D गहराई को नियंत्रित करती है। उच्च संख्यात्मक `z-index` (जैसे, 999) वाले तत्व निम्न मानों (जैसे, 1) वाले तत्वों को ओवरलैप और कवर करेंगे। महत्वपूर्ण बात यह है कि ब्राउज़र द्वारा `z-index` को गणितीय रूप से अनदेखा कर दिया जाता है जब तक कि तत्व की `position` सापेक्ष, पूर्ण, निश्चित या चिपचिपा (relative, absolute, fixed, sticky) पर सेट न हो।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly advanced CSS syntax rule allows developers to execute entirely different blocks of CSS code conditionally, based on the physical screen width of the user's device?",opts:["@responsive","@media","@screen-width","@viewport"],ans:1,exp:"The `@media` rule (Media Queries) is the absolute core engine of Responsive Web Design. By writing logic like `@media (max-width: 768px)`, the browser checks the hardware screen width. If the phone screen is smaller than 768px, the browser dynamically applies a totally different CSS block, instantly transforming the layout for mobile."},hi:{q:"कौन सा अत्यधिक उन्नत CSS सिंटैक्स नियम डेवलपर्स को उपयोगकर्ता के डिवाइस की भौतिक स्क्रीन चौड़ाई के आधार पर सशर्त रूप से CSS कोड के पूरी तरह से अलग ब्लॉक निष्पादित करने की अनुमति देता है?",opts:["@responsive","@media","@screen-width","@viewport"],ans:1,exp:"`@media` नियम (मीडिया क्वेरीज़) रिस्पॉन्सिव वेब डिज़ाइन का पूर्ण मुख्य इंजन है। `@media (max-width: 768px)` जैसा तर्क लिखकर, ब्राउज़र हार्डवेयर स्क्रीन की चौड़ाई की जाँच करता है। यदि फ़ोन स्क्रीन 768px से छोटी है, तो ब्राउज़र गतिशील रूप से एक अलग CSS ब्लॉक लागू करता है।"}},
{type:"mcq",diff:"hard",en:{q:"To aggressively prevent a user from submitting an HTML form while a specific critical input field remains empty, which boolean attribute is utilized?",opts:["mandatory","validate","required","must-fill"],ans:2,exp:"Injecting the `required` boolean attribute into an `<input>` tag natively hijacks the browser's form submission engine. If the user clicks submit while the field is blank, the browser physically halts the HTTP POST request, highlights the blank box, and generates a localized pop-up warning demanding input."},hi:{q:"विशिष्ट महत्वपूर्ण इनपुट फ़ील्ड के खाली रहने के दौरान उपयोगकर्ता को HTML फ़ॉर्म सबमिट करने से आक्रामक रूप से रोकने के लिए, किस बूलियन विशेषता (boolean attribute) का उपयोग किया जाता है?",opts:["mandatory","validate","required","must-fill"],ans:2,exp:"`<input>` टैग में `required` बूलियन एट्रिब्यूट को इंजेक्ट करना मूल रूप से ब्राउज़र के फॉर्म सबमिशन इंजन को हाईजैक कर लेता है। यदि उपयोगकर्ता फ़ील्ड खाली होने के दौरान सबमिट पर क्लिक करता है, तो ब्राउज़र भौतिक रूप से HTTP POST अनुरोध को रोकता है, खाली बॉक्स को हाइलाइट करता है, और एक पॉप-अप चेतावनी उत्पन्न करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which modern HTML5 form input type specifically restricts the user to typing digits, and natively generates UI up/down arrows on desktop browsers?",opts:["type=\"digits\"","type=\"integer\"","type=\"math\"","type=\"number\""],ans:3,exp:"The `<input type=\"number\">` instantly alters browser behavior. It physically blocks the user from typing alphabetical letters. On desktop browsers, it generates 'spinner' UI arrows to increment values. On mobile phones, it intelligently triggers the specialized numeric keypad to pop up, massively improving user experience."},hi:{q:"कौन सा आधुनिक HTML5 फॉर्म इनपुट प्रकार विशेष रूप से उपयोगकर्ता को अंक (digits) टाइप करने तक सीमित करता है, और मूल रूप से डेस्कटॉप ब्राउज़रों पर UI अप/डाउन तीर उत्पन्न करता है?",opts:["type=\"digits\"","type=\"integer\"","type=\"math\"","type=\"number\""],ans:3,exp:"`<input type=\"number\">` तुरंत ब्राउज़र के व्यवहार को बदल देता है। यह भौतिक रूप से उपयोगकर्ता को वर्णमाला के अक्षर टाइप करने से रोकता है। डेस्कटॉप ब्राउज़रों पर, यह मान बढ़ाने के लिए 'स्पिनर' UI तीर उत्पन्न करता है। मोबाइल फोन पर, यह विशेष संख्यात्मक कीपैड को पॉप अप करने के लिए ट्रिगर करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly destructive CSS declaration completely removes an element from the visual screen AND violently deletes the geometric space it formally occupied, causing other elements to collapse into its void?",opts:["visibility: hidden;","opacity: 0;","display: none;","z-index: -1;"],ans:2,exp:"`display: none;` is brutal. The rendering engine completely strips the element from the visual layout tree. The element becomes invisible, but more importantly, its physical height and width are crushed to zero. Neighboring elements immediately snap into the empty space as if the element never existed in the HTML code."},hi:{q:"कौन सी अत्यधिक विनाशकारी CSS घोषणा किसी तत्व को दृश्य स्क्रीन से पूरी तरह से हटा देती है और औपचारिक रूप से उसके द्वारा घेरे गए ज्यामितीय स्थान को हिंसक रूप से हटा देती है, जिससे अन्य तत्व उसके शून्य में ढह जाते हैं?",opts:["visibility: hidden;","opacity: 0;","display: none;","z-index: -1;"],ans:2,exp:"`display: none;` क्रूर है। रेंडरिंग इंजन दृश्य लेआउट पेड़ से तत्व को पूरी तरह से हटा देता है। तत्व अदृश्य हो जाता है, लेकिन अधिक महत्वपूर्ण बात यह है कि इसकी भौतिक ऊंचाई और चौड़ाई शून्य हो जाती है। पड़ोसी तत्व तुरंत खाली स्थान में स्नैप करते हैं जैसे कि एचटीएमएल कोड में तत्व कभी मौजूद नहीं था।"}},
{type:"mcq",diff:"hard",en:{q:"Conversely, which CSS declaration turns an element completely invisible, but strictly preserves its physical geometric footprint, leaving a blank hole in the page layout?",opts:["display: hidden;","visibility: hidden;","display: none;","opacity: invisible;"],ans:1,exp:"`visibility: hidden;` acts like an invisibility cloak. The browser still meticulously calculates the element's height, width, padding, and margins, and physically reserves that exact block of space in the layout geometry. However, the pixels are rendered fully transparent, creating a structural hole that surrounding elements cannot collapse into."},hi:{q:"इसके विपरीत, कौन सी CSS घोषणा किसी तत्व को पूरी तरह से अदृश्य कर देती है, लेकिन पृष्ठ लेआउट में एक खाली छेद (blank hole) छोड़ते हुए, उसके भौतिक ज्यामितीय पदचिह्न को सख्ती से संरक्षित करती है?",opts:["display: hidden;","visibility: hidden;","display: none;","opacity: invisible;"],ans:1,exp:"`visibility: hidden;` एक अदृश्यता लबादे की तरह काम करता है। ब्राउज़र अभी भी तत्व की ऊंचाई, चौड़ाई, पैडिंग और मार्जिन की सावधानीपूर्वक गणना करता है, और लेआउट ज्यामिति में उस सटीक ब्लॉक को भौतिक रूप से सुरक्षित रखता है। हालाँकि, पिक्सेल पूरी तरह से पारदर्शी हो जाते हैं, एक संरचनात्मक छेद बनाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In modern CSS architecture, what specific prefix syntax is strictly required to declare a custom CSS Variable (Custom Property)?",opts:["$var-name","@var-name","--var-name","#var-name"],ans:2,exp:"CSS Custom Properties (Variables) revolutionize CSS maintainability. To define a variable locally or globally (usually inside the `:root` pseudo-class), the exact syntax mandates a double hyphen prefix (e.g., `--main-theme-color: #336699;`). This value can then be dynamically retrieved hundreds of times using the `var(--main-theme-color)` function."},hi:{q:"आधुनिक CSS आर्किटेक्चर में, कस्टम CSS वेरिएबल (Custom Property) घोषित करने के लिए विशेष रूप से किस उपसर्ग सिंटैक्स (prefix syntax) की आवश्यकता होती है?",opts:["$var-name","@var-name","--var-name","#var-name"],ans:2,exp:"CSS कस्टम गुण (चर) CSS रखरखाव में क्रांति लाते हैं। स्थानीय या विश्व स्तर पर चर को परिभाषित करने के लिए, सटीक सिंटैक्स एक डबल हाइफ़न उपसर्ग (उदा., `--main-theme-color: #336699;`) को अनिवार्य करता है। इस मान को बाद में `var(--main-theme-color)` फ़ंक्शन का उपयोग करके सैकड़ों बार पुनर्प्राप्त किया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In CSS Flexbox architecture, which property governs the alignment and distribution of flexible items along the 'Main Axis' (horizontally by default)?",opts:["align-items","justify-content","flex-direction","align-content"],ans:1,exp:"The `justify-content` property is the absolute master of the Main Axis in a Flexbox container. If the layout is a row, it mathematically distributes horizontal space. Values like `center` shove items to the middle, while `space-between` violently pushes the first and last items to the container's extreme opposite edges, distributing equal blank space between the rest."},hi:{q:"CSS फ्लेक्सबॉक्स (Flexbox) आर्किटेक्चर में, कौन सी प्रॉपर्टी 'मेन एक्सिस' (Main Axis) (डिफ़ॉल्ट रूप से क्षैतिज रूप से) के साथ लचीले आइटम के संरेखण और वितरण को नियंत्रित करती है?",opts:["align-items","justify-content","flex-direction","align-content"],ans:1,exp:"`justify-content` संपत्ति फ्लेक्सबॉक्स कंटेनर में मुख्य धुरी का पूर्ण मास्टर है। यदि लेआउट एक पंक्ति है, तो यह गणितीय रूप से क्षैतिज स्थान वितरित करता है। 'केंद्र' जैसे मान वस्तुओं को बीच में धकेलते हैं, जबकि `space-between` पहली और अंतिम वस्तुओं को कंटेनर के चरम विपरीत किनारों पर धकेलते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In CSS Flexbox, which property strictly controls the alignment of items along the perpendicular 'Cross Axis' (vertically by default)?",opts:["justify-content","align-content","align-items","flex-wrap"],ans:2,exp:"While justify-content handles the Main Axis, `align-items` governs the perpendicular Cross Axis. In a standard flex row, `align-items` controls vertical alignment. Setting `align-items: center;` mathematically forces all internal items to slide up or down until they are perfectly centered relative to the container's total physical height."},hi:{q:"CSS Flexbox में, कौन सी संपत्ति लंबवत 'क्रॉस एक्सिस' (Cross Axis) (डिफ़ॉल्ट रूप से लंबवत) के साथ आइटम के संरेखण (alignment) को सख्ती से नियंत्रित करती है?",opts:["justify-content","align-content","align-items","flex-wrap"],ans:2,exp:"जबकि justify-content मुख्य अक्ष को संभालता है, `align-items` लंबवत क्रॉस एक्सिस को नियंत्रित करता है। एक मानक फ्लेक्स पंक्ति में, `align-items` ऊर्ध्वाधर संरेखण को नियंत्रित करता है। `align-items: center;` सेट करने से गणितीय रूप से सभी आंतरिक वस्तुओं को ऊपर या नीचे खिसकने के लिए मजबूर किया जाता है जब तक कि वे पूरी तरह से केंद्रित न हो जाएं।"}},
{type:"mcq",diff:"hard",en:{q:"Which immensely powerful CSS Grid property allows developers to explicitly define the number, sizing, and fractional ratios of vertical layout columns?",opts:["grid-template-rows","grid-columns-count","grid-template-columns","grid-area"],ans:2,exp:"The `grid-template-columns` property defines the exact architectural matrix of a Grid container. Developers can construct complex layouts by defining widths, such as `grid-template-columns: 200px 1fr 1fr;`. This commands the engine to lock the first column at 200px, and dynamically split all remaining mathematical screen width equally between the last two columns."},hi:{q:"कौन सी अत्यधिक शक्तिशाली CSS ग्रिड (CSS Grid) संपत्ति डेवलपर्स को लंबवत लेआउट कॉलम की संख्या, आकार और भिन्नात्मक अनुपात को स्पष्ट रूप से परिभाषित करने की अनुमति देती है?",opts:["grid-template-rows","grid-columns-count","grid-template-columns","grid-area"],ans:2,exp:"`grid-template-columns` संपत्ति एक ग्रिड कंटेनर के सटीक वास्तुशिल्प मैट्रिक्स को परिभाषित करती है। डेवलपर्स चौड़ाई को परिभाषित करके जटिल लेआउट का निर्माण कर सकते हैं, जैसे `grid-template-columns: 200px 1fr 1fr;`। यह इंजन को पहले कॉलम को 200px पर लॉक करने का आदेश देता है, और गतिशील रूप से शेष सभी चौड़ाई को अंतिम दो कॉलमों के बीच समान रूप से विभाजित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which HTML5 semantic tag is engineered strictly to encapsulate independent, self-contained, completely reusable pieces of content (like a blog post or news story)?",opts:["<section>","<div>","<article>","<main>"],ans:2,exp:"The `<article>` tag is a highly specific structural wrapper. It communicates to search engines that the enclosed content is completely self-contained and could theoretically be syndicated, shared, or republished independently from the rest of the site's layout. It is the gold standard for formatting individual blog posts or forum comments."},hi:{q:"कौन सा HTML5 सिमेंटिक टैग कड़ाई से सामग्री के स्वतंत्र, स्वयं-निहित, पूरी तरह से पुन: प्रयोज्य टुकड़ों (जैसे ब्लॉग पोस्ट या समाचार कहानी) को एनकैप्सुलेट करने के लिए इंजीनियर किया गया है?",opts:["<section>","<div>","<article>","<main>"],ans:2,exp:"`<article>` टैग एक उच्च विशिष्ट संरचनात्मक आवरण है। यह खोज इंजनों को संप्रेषित करता है कि संलग्न सामग्री पूरी तरह से स्व-निहित है और सैद्धांतिक रूप से साइट के बाकी लेआउट से स्वतंत्र रूप से सिंडिकेट, साझा या पुनर्प्रकाशित की जा सकती है। यह अलग-अलग ब्लॉग पोस्ट को प्रारूपित करने के लिए स्वर्ण मानक है।"}},
{type:"mcq",diff:"hard",en:{q:"Which HTML5 semantic tag is used to designate structural content that is tangentially related to the main page content, often visually rendered as a Sidebar?",opts:["<sidebar>","<aside>","<panel>","<menu>"],ans:1,exp:"The `<aside>` element conceptually isolates secondary content. While the main article drives the page's core message, the `<aside>` holds tangentially related pull-quotes, author bios, or related link menus. Web designers traditionally float or absolute-position the `<aside>` tag to the left or right edge, creating the classic 'Sidebar' layout."},hi:{q:"किस HTML5 सिमेंटिक टैग का उपयोग संरचनात्मक सामग्री को नामित करने के लिए किया जाता है जो मुख्य पृष्ठ सामग्री से संबंधित है, जिसे अक्सर साइडबार (Sidebar) के रूप में दृश्य रूप से प्रस्तुत किया जाता है?",opts:["<sidebar>","<aside>","<panel>","<menu>"],ans:1,exp:"`<aside>` तत्व वैचारिक रूप से द्वितीयक सामग्री को अलग करता है। जबकि मुख्य लेख पृष्ठ के मुख्य संदेश को संचालित करता है, `<aside>` संबंधित पुल-कोट्स, लेखक बायोस या संबंधित लिंक मेनू रखता है। वेब डिज़ाइनर पारंपरिक रूप से क्लासिक 'साइडबार' लेआउट बनाते हुए, `<aside>` टैग को बाएं या दाएं किनारे पर फ्लोट या पूर्ण-स्थिति में रखते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"By applying `box-sizing: border-box;` in CSS, how does the browser's layout engine mathematically alter its width calculation?",opts:["It removes borders entirely","It adds margin to the width calculation","It forces the stated width to include both the internal padding and the physical border thickness, preventing the element from geometrically blowing up","It makes the box perfectly circular"],ans:2,exp:"This is the most critical CSS layout fix. By default (content-box), adding 20px padding to a 200px wide box makes it geometrically 240px wide, breaking layouts. `border-box` fundamentally rewrites this math. It forces the internal padding and external border to shrink inward, mathematically locking the total physical footprint to the stated 200px."},hi:{q:"CSS में `box-sizing: border-box;` लागू करके, ब्राउज़र का लेआउट इंजन गणितीय रूप से अपनी चौड़ाई की गणना को कैसे बदलता है?",opts:["यह बॉर्डर को पूरी तरह हटा देता है","यह चौड़ाई की गणना में मार्जिन जोड़ता है","यह तत्व को ज्यामितीय रूप से उड़ने से रोकने के लिए, आंतरिक पैडिंग और भौतिक सीमा की मोटाई दोनों को शामिल करने के लिए बताई गई चौड़ाई को मजबूर करता है","यह बॉक्स को पूरी तरह गोलाकार बनाता है"],ans:2,exp:"यह सबसे महत्वपूर्ण CSS लेआउट फिक्स है। डिफ़ॉल्ट रूप से, 200px चौड़े बॉक्स में 20px पैडिंग जोड़ने से यह 240px चौड़ा हो जाता है, जिससे लेआउट टूट जाता है। `border-box` मूल रूप से इस गणित को फिर से लिखता है। यह आंतरिक पैडिंग और बाहरी सीमा को अंदर की ओर सिकुड़ने के लिए मजबूर करता है, जिससे कुल भौतिक पदचिह्न 200px पर लॉक हो जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly specific tag acts as a 'portal', allowing developers to embed an entirely functional, separate HTML webpage directly inside a framed box on the current page?",opts:["<embed>","<object>","<iframe>","<portal>"],ans:2,exp:"The `<iframe>` (Inline Frame) tag opens a secure dimensional portal to another server. By writing `<iframe src=\"https://youtube.com/...\">`, the browser opens a rigid rectangular window and renders the external website completely independently within the parent page's DOM, natively used for embedding Google Maps or video players."},hi:{q:"कौन सा अत्यधिक विशिष्ट टैग 'पोर्टल' के रूप में कार्य करता है, जिससे डेवलपर्स को वर्तमान पृष्ठ पर एक फ़्रेमयुक्त बॉक्स के अंदर सीधे एक पूरी तरह कार्यात्मक, अलग HTML वेबपेज एम्बेड करने की अनुमति मिलती है?",opts:["<embed>","<object>","<iframe>","<portal>"],ans:2,exp:"`<iframe>` (इनलाइन फ़्रेम) टैग किसी अन्य सर्वर के लिए एक सुरक्षित आयामी पोर्टल खोलता है। `<iframe src=\"https://youtube.com/...\">` लिखकर, ब्राउज़र एक कठोर आयताकार खिड़की खोलता है और बाहरी वेबसाइट को मूल पृष्ठ के DOM के भीतर पूरी तरह से स्वतंत्र रूप से प्रस्तुत करता है, जिसका उपयोग Google मानचित्र या वीडियो प्लेयर एम्बेड करने के लिए किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In CSS typography architecture, what mathematical difference separates the `em` relative unit from the `rem` relative unit?",opts:["em is based on pixels; rem is based on inches","em calculates its size relative to its direct parent element causing massive compounding issues; rem strictly calculates relative to the root `<html>` element providing stability","There is no difference","em works only on text; rem works on images"],ans:1,exp:"The `em` unit multiplies based on its immediate parent container. If a parent is 20px, a child set to 2em becomes 40px. Nested deep enough, `em` cascades uncontrollably into massive text sizes. The `rem` (Root EM) radically solves this by ignoring parents and multiplying strictly against the baseline font size declared in the main `<html>` tag."},hi:{q:"CSS टाइपोग्राफी आर्किटेक्चर में, कौन सा गणितीय अंतर `em` सापेक्ष इकाई (relative unit) को `rem` सापेक्ष इकाई से अलग करता है?",opts:["em पिक्सेल पर आधारित है; rem इंच पर आधारित है","em अपने प्रत्यक्ष मूल तत्व के सापेक्ष अपने आकार की गणना करता है जिससे बड़े पैमाने पर कंपाउंडिंग समस्याएँ पैदा होती हैं; rem कड़ाई से स्थिरता प्रदान करने वाले रूट `<html>` तत्व के सापेक्ष गणना करता है","कोई अंतर नहीं है","em केवल टेक्स्ट पर काम करता है; rem छवियों पर काम करता है"],ans:1,exp:"`em` इकाई अपने तत्काल मूल कंटेनर के आधार पर गुणा करती है। नेस्टेड गहरा होने पर, `em` अनियंत्रित रूप से बड़े पाठ आकारों में कैस्केड होता है। `rem` (रूट EM) माता-पिता को अनदेखा करके और मुख्य `<html>` टैग में घोषित बेसलाइन फ़ॉन्ट आकार के खिलाफ कड़ाई से गुणा करके इस समस्या को मौलिक रूप से हल करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which extremely precise CSS Pseudo-element specifically isolates and targets only the very first character of a block of text, traditionally used to create a giant 'Drop Cap' effect?",opts:[":first-child","::first-letter","::first-line",":first-type"],ans:1,exp:"Pseudo-elements (denoted by a double colon `::`) target sub-parts of an element that do not exist structurally in the HTML tree. The `p::first-letter` selector mathematically isolates the very first character of a paragraph. Developers apply massive font sizes and floats to this pseudo-element to create classic magazine-style 'Drop Caps'."},hi:{q:"कौन सा अत्यंत सटीक CSS स्यूडो-एलिमेंट (Pseudo-element) विशेष रूप से पाठ के एक ब्लॉक के केवल पहले अक्षर (first character) को अलग और लक्षित करता है, पारंपरिक रूप से एक विशाल 'ड्रॉप कैप' (Drop Cap) प्रभाव बनाने के लिए उपयोग किया जाता है?",opts:[":first-child","::first-letter","::first-line",":first-type"],ans:1,exp:"छद्म-तत्व (एक डबल कोलन `::` द्वारा निरूपित) एक तत्व के उप-भागों को लक्षित करते हैं जो संरचनात्मक रूप से HTML पेड़ में मौजूद नहीं हैं। `p::first-letter` चयनकर्ता गणितीय रूप से अनुच्छेद के पहले अक्षर को अलग करता है। डेवलपर्स क्लासिक पत्रिका-शैली 'ड्रॉप कैप्स' बनाने के लिए इस छद्म-तत्व में बड़े फ़ॉन्ट आकार और फ़्लोट लागू करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"According to strict W3C HTML specifications, which tag must instantly follow the opening `<table>` tag to provide a legally semantic title or explanatory heading specifically bound to that data table?",opts:["<thead>","<th>","<caption>","<title>"],ans:2,exp:"The `<caption>` tag is the structural metadata anchor for a table. To be valid HTML, if a caption is used, it must be the absolute very first tag immediately following the `<table>` opening tag. It provides a visual title and crucial screen-reader context explicitly tying the text logically to the massive data grid below it."},hi:{q:"कठोर W3C HTML विनिर्देशों के अनुसार, कौन सा टैग `<table>` टैग के तुरंत बाद आना चाहिए, ताकि विशेष रूप से उस डेटा तालिका से जुड़ा एक कानूनी सिमेंटिक शीर्षक या व्याख्यात्मक शीर्षक (caption) प्रदान किया जा सके?",opts:["<thead>","<th>","<caption>","<title>"],ans:2,exp:"`<caption>` टैग एक तालिका के लिए संरचनात्मक मेटाडेटा एंकर है। वैध HTML होने के लिए, यदि किसी कैप्शन का उपयोग किया जाता है, तो यह `<table>` ओपनिंग टैग के तुरंत बाद पूर्ण रूप से पहला टैग होना चाहिए। यह एक दृश्य शीर्षक और महत्वपूर्ण स्क्रीन-रीडर संदर्भ प्रदान करता है जो पाठ को तार्किक रूप से इसके नीचे विशाल डेटा ग्रिड से जोड़ता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which modern HTML5 tag explicitly demarcates the absolute bottom section of a webpage or an article, natively intended to hold copyright data, legal links, or author contacts?",opts:["<bottom>","<end>","<footer>","<base>"],ans:2,exp:"The `<footer>` is a semantic landmark element. It explicitly signals to the DOM parser that the enclosed structure sits at the bottom of its parent section. While it fundamentally behaves like a basic `<div>` visually, using `<footer>` massively upgrades the document's SEO hierarchy and structural accessibility mapping for disabled users."},hi:{q:"कौन सा आधुनिक HTML5 टैग स्पष्ट रूप से वेबपेज या लेख के पूर्ण निचले भाग (bottom section) का सीमांकन करता है, जो मूल रूप से कॉपीराइट डेटा, कानूनी लिंक या लेखक संपर्कों को रखने के लिए अभिप्रेत है?",opts:["<bottom>","<end>","<footer>","<base>"],ans:2,exp:"`<footer>` एक अर्थपूर्ण लैंडमार्क तत्व है। यह स्पष्ट रूप से डीओएम पार्सर को संकेत देता है कि संलग्न संरचना अपने मूल अनुभाग के नीचे बैठती है। यद्यपि यह मूल रूप से दृश्य रूप से एक बुनियादी `<div>` की तरह व्यवहार करता है, `<footer>` का उपयोग करने से विकलांग उपयोगकर्ताओं के लिए दस्तावेज़ के SEO पदानुक्रम को बड़े पैमाने पर अपग्रेड किया जाता है।"}},
{type:"tf",diff:"hard",en:{q:"Block-level HTML elements natively shrink-wrap their width to match their internal text content, while Inline elements naturally expand to 100% of the screen width.",opts:["True","False"],ans:1,exp:"False. The physical layout rules are the exact reverse. Block-level elements (like `<div>` and `<h1>`) aggressively expand horizontally to violently consume 100% of available parent width. Inline elements (like `<span>` and `<a>`) passively shrink-wrap, mathematically consuming only the exact pixel width required to cover their contained text."},hi:{q:"ब्लॉक-स्तरीय HTML तत्व मूल रूप से अपनी आंतरिक पाठ सामग्री से मेल खाने के लिए अपनी चौड़ाई को सिकोड़ते (shrink-wrap) हैं, जबकि इनलाइन तत्व स्वाभाविक रूप से स्क्रीन की चौड़ाई के 100% तक फैलते हैं।",opts:["सही","गलत"],ans:1,exp:"गलत। भौतिक लेआउट नियम ठीक इसके विपरीत हैं। ब्लॉक-स्तरीय तत्व (जैसे `<div>` और `<h1>`) उपलब्ध मूल चौड़ाई का 100% हिंसक रूप से उपभोग करने के लिए क्षैतिज रूप से आक्रामक रूप से विस्तार करते हैं। इनलाइन तत्व (जैसे `<span>` और `<a>`) निष्क्रिय रूप से सिकुड़ते हैं, गणितीय रूप से उनके निहित पाठ को कवर करने के लिए आवश्यक सटीक पिक्सेल चौड़ाई का उपभोग करते हैं।"}},
{type:"tf",diff:"hard",en:{q:"The CSS `z-index` property absolutely cannot mathematically function if the targeted element has its `position` property set to the default value of `static`.",opts:["True","False"],ans:0,exp:"True. The `z-index` depth sorting algorithm mathematically requires an element to be physically broken out of the static 2D document flow. If an element remains `position: static` (the default), the browser's rendering engine entirely ignores any `z-index` declarations. It must be shifted to relative, absolute, fixed, or sticky to stack."},hi:{q:"CSS `z-index` संपत्ति गणितीय रूप से काम नहीं कर सकती है यदि लक्षित तत्व की `position` संपत्ति `static` के डिफ़ॉल्ट मान पर सेट है।",opts:["सही","गलत"],ans:0,exp:"सही। `z-index` गहराई छँटाई एल्गोरिथ्म गणितीय रूप से एक तत्व को स्थैतिक 2D दस्तावेज़ प्रवाह से भौतिक रूप से बाहर तोड़ने की आवश्यकता है। यदि कोई तत्व `position: static` (डिफ़ॉल्ट) रहता है, तो ब्राउज़र का रेंडरिंग इंजन किसी भी `z-index` घोषणाओं को पूरी तरह से अनदेखा कर देता है।"}},
{type:"tf",diff:"hard",en:{q:"Applying the `!important` rule to a CSS declaration (e.g., `color: red !important;`) forcefully bypasses the entire specificity hierarchy, instantly annihilating even highly specific Inline styles.",opts:["True","False"],ans:0,exp:"True. The `!important` flag is the nuclear option in CSS architecture. It violently overrides the strict mathematical specificity calculations (ID vs Class vs Inline). If a generic tag selector utilizes `!important`, it will effortlessly overwrite an inline `style=\"\"` attribute, which normally possesses unbreakable 1000-point specificity."},hi:{q:"CSS घोषणा में `!important` नियम लागू करना (उदा., `color: red !important;`) बलपूर्वक संपूर्ण विशिष्टता पदानुक्रम (specificity hierarchy) को बायपास करता है, तुरंत अत्यधिक विशिष्ट इनलाइन (Inline) शैलियों को भी नष्ट कर देता है।",opts:["सही","गलत"],ans:0,exp:"सही। `!important` ध्वज CSS वास्तुकला में परमाणु विकल्प है। यह हिंसक रूप से सख्त गणितीय विशिष्टता गणनाओं (ID बनाम Class बनाम Inline) को ओवरराइड करता है। यदि एक सामान्य टैग चयनकर्ता `!important` का उपयोग करता है, तो यह आसानी से एक इनलाइन `style=\"\"` विशेषता को अधिलेखित कर देगा, जिसमें सामान्य रूप से अटूट 1000-बिंदु विशिष्टता होती है।"}},
{type:"tf",diff:"hard",en:{q:"By native browser mechanics, placing a simple `<button>` tag inside a `<form>` block automatically turns it into a 'Submit' button that will aggressively try to refresh the page and send data.",opts:["True","False"],ans:0,exp:"True. By strict HTML5 specifications, any `<button>` placed internally within a `<form>` container inherently adopts `type=\"submit\"` as its default physical state. If clicked, the browser intercepts the click, instantly halts normal JS execution, and violently triggers an HTTP POST/GET request to the form's `action` URL, reloading the page."},hi:{q:"मूल ब्राउज़र यांत्रिकी द्वारा, `<form>` ब्लॉक के अंदर एक साधारण `<button>` टैग रखने से यह स्वचालित रूप से एक 'सबमिट' बटन में बदल जाता है जो आक्रामक रूप से पृष्ठ को रीफ्रेश करने और डेटा भेजने का प्रयास करेगा।",opts:["सही","गलत"],ans:0,exp:"सही। सख्त HTML5 विनिर्देशों के अनुसार, `<form>` कंटेनर के भीतर आंतरिक रूप से रखा गया कोई भी `<button>` स्वाभाविक रूप से `type=\"submit\"` को अपनी डिफ़ॉल्ट भौतिक स्थिति के रूप में अपनाता है। यदि क्लिक किया जाता है, तो ब्राउज़र क्लिक को रोकता है, और फॉर्म के `action` URL पर एक HTTP POST/GET अनुरोध को हिंसक रूप से ट्रिगर करता है, पृष्ठ को पुनः लोड करता है।"}},
{type:"tf",diff:"hard",en:{q:"When evaluating complex CSS selectors like `.container ul li a`, the browser's rendering engine reads and targets the elements sequentially from left to right.",opts:["True","False"],ans:1,exp:"False. The browser's CSS matching engine mathematically operates from Right-to-Left (the 'Key Selector' principle). In the rule `.container ul li a`, the engine first violently sweeps the entire DOM to find EVERY `<a>` tag. Only then does it move leftwards, filtering out the ones that aren't inside an `<li>`, then `<ul>`, up to `.container`."},hi:{q:"जटिल CSS चयनकर्ताओं (जैसे `.container ul li a`) का मूल्यांकन करते समय, ब्राउज़र का रेंडरिंग इंजन क्रमिक रूप से तत्वों को बाएँ से दाएँ (left to right) पढ़ता और लक्षित करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। ब्राउज़र का CSS मिलान इंजन गणितीय रूप से दाएँ-से-बाएँ ('की सेलेक्टर' सिद्धांत) संचालित होता है। `.container ul li a` नियम में, इंजन पहले हर `<a>` टैग को खोजने के लिए पूरे DOM को हिंसक रूप से साफ करता है। उसके बाद ही यह बाईं ओर बढ़ता है, उन लोगों को फ़िल्टर करता है जो `<li>`, फिर `<ul>` के अंदर नहीं हैं।"}}
,
{type:"mcq",diff:"hard",en:{q:"In CSS, what is the precise difference between 'display:none' and 'visibility:hidden' when applied to an HTML element?",opts:["Both are completely identical in effect","display:none removes the element from document flow occupying no space; visibility:hidden hides the element visually but it still occupies its original space in the layout","visibility:hidden removes element from document flow; display:none only hides visually","display:none only works on block elements; visibility:hidden works on all elements"],ans:1,exp:"These two CSS properties hide elements differently. 'display:none' completely removes the element from the document flow — it becomes invisible AND takes up zero space, as if it doesn't exist in the layout. Other elements reflow to fill its space. 'visibility:hidden' makes the element invisible but it still occupies its original space in the layout — a blank gap remains where the element was. This distinction is critical for animations, dynamic UI, and accessibility in web design."},hi:{q:"CSS में 'display:none' और 'visibility:hidden' को HTML element पर apply करने पर सटीक अंतर क्या है?",opts:["दोनों प्रभाव में पूरी तरह समान हैं","display:none element को document flow से हटाता है कोई space नहीं; visibility:hidden element को visually छुपाता है लेकिन यह layout में अपनी मूल space अभी भी घेरता है","visibility:hidden element को document flow से हटाता है; display:none केवल visually छुपाता है","display:none केवल block elements पर काम करता है; visibility:hidden सभी elements पर"],ans:1,exp:"ये दो CSS properties element को अलग-अलग तरीके से छुपाती हैं। 'display:none' element को document flow से पूरी तरह हटाता है — यह invisible हो जाता है और शून्य space लेता है। अन्य elements उसकी space भरने के लिए reflow करते हैं। 'visibility:hidden' element को invisible बनाता है लेकिन यह layout में अपनी मूल space घेरता रहता है — जहाँ element था वहाँ blank gap रहती है। Web design में animations और dynamic UI के लिए यह अंतर महत्वपूर्ण है।"}}
];